INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(1, 'Siapakah penulis buku referensi Pramuka "Boyman"?', '["A. Sri Sultan Hamengkubuwono IX", "B. Baden Powell", "C. Andri Bob Sunardi", "D. Azrul Azwar"]'::jsonb, 'C. Andri Bob Sunardi'),
(1, 'Sifat kepramukaan yang penyelenggaraannya disesuaikan dengan keadaan dan kebutuhan masyarakat di negaranya adalah sifat...', '["A. Universal", "B. Nasional", "C. Internasional", "D. Fleksibel"]'::jsonb, 'B. Nasional'),
(1, 'Kepramukaan dapat berlaku untuk siapa saja dan diselenggarakan di mana saja. Ini disebut sifat...', '["A. Universal", "B. Nasional", "C. Internasional", "D. Terbuka"]'::jsonb, 'A. Universal'),
(1, 'Kepramukaan harus dapat mengembangkan rasa persaudaraan dan persahabatan antar sesama manusia. Ini adalah cerminan dari sifat...', '["A. Nasional", "B. Internasional", "C. Universal", "D. Mandiri"]'::jsonb, 'B. Internasional'),
(1, 'Fungsi kepramukaan bagi peserta didik (anak/pemuda) pada dasarnya adalah sebagai...', '["A. Kewajiban", "B. Pekerjaan", "C. Permainan yang menarik", "D. Pengabdian"]'::jsonb, 'C. Permainan yang menarik'),
(1, 'Bagi orang dewasa, kepramukaan bukan lagi permainan, melainkan suatu tugas yang memerlukan keikhlasan. Ini adalah fungsi sebagai...', '["A. Pekerjaan", "B. Pengabdian", "C. Kewajiban", "D. Hiburan"]'::jsonb, 'B. Pengabdian'),
(1, 'Kepramukaan berfungsi sebagai alat untuk memenuhi kebutuhan dan tujuan masyarakat. Ini adalah fungsi kepramukaan bagi...', '["A. Pemuda", "B. Pembina", "C. Orang Dewasa", "D. Masyarakat dan Organisasi"]'::jsonb, 'D. Masyarakat dan Organisasi'),
(1, 'Proses pendidikan di luar lingkungan sekolah dan keluarga dalam bentuk kegiatan menarik di alam terbuka disebut...', '["A. Gerakan Pramuka", "B. Kepramukaan", "C. Pramuka", "D. Kepanduan"]'::jsonb, 'B. Kepramukaan'),
(1, 'Orang-orang atau anggota yang mengikuti kegiatan dan tergabung di dalam organisasi kepanduan di Indonesia disebut...', '["A. Pramuka", "B. Gerakan Pramuka", "C. Kepramukaan", "D. Pandu"]'::jsonb, 'A. Pramuka'),
(1, 'Organisasi atau wadah resmi yang menyelenggarakan pendidikan kepramukaan di Indonesia adalah...', '["A. Kepanduan Nasional", "B. Kepramukaan", "C. Gerakan Pramuka", "D. Pramuka Garuda"]'::jsonb, 'C. Gerakan Pramuka'),
(1, 'Kepanjangan dari PRAMUKA adalah...', '["A. Praja Muda Karana", "B. Pemuda Rajin Berkarya", "C. Praja Muda Karya", "D. Pandu Rakyat Muda"]'::jsonb, 'A. Praja Muda Karana'),
(1, 'Istilah Praja Muda Karana memiliki arti...', '["A. Pemuda yang suka bekerja keras", "B. Rakyat muda yang suka berkarya", "C. Pemuda yang berjiwa ksatria", "D. Rakyat muda yang mandiri"]'::jsonb, 'B. Rakyat muda yang suka berkarya'),
(1, 'Bapak Pramuka Indonesia adalah...', '["A. Soekarno", "B. Jenderal Soedirman", "C. Sri Sultan Hamengkubuwono IX", "D. Ki Hajar Dewantara"]'::jsonb, 'C. Sri Sultan Hamengkubuwono IX'),
(1, 'Bapak Pandu Dunia (Chief Scout of the World) adalah...', '["A. Lord Robert Baden Powell", "B. William Smyth", "C. Ernest Thompson Seton", "D. Daniel Carter Beard"]'::jsonb, 'A. Lord Robert Baden Powell'),
(1, 'Tujuan Gerakan Pramuka yang pertama adalah membentuk anggota pramuka agar memiliki kepribadian yang...', '["A. Kaya raya", "B. Cerdas secara akademis", "C. Beriman, bertakwa, dan berakhlak mulia", "D. Terkenal di masyarakat"]'::jsonb, 'C. Beriman, bertakwa, dan berakhlak mulia'),
(1, 'Tujuan Gerakan Pramuka yang kedua adalah agar anggota pramuka menjadi warga negara yang...', '["A. Bebas aturan", "B. Berjiwa Pancasila", "C. Suka merantau", "D. Cepat bekerja"]'::jsonb, 'B. Berjiwa Pancasila'),
(1, 'Salah satu pilar metode kepramukaan adalah "Learning by Doing", yang artinya...', '["A. Belajar di dalam kelas", "B. Belajar sambil melakukan", "C. Belajar melalui teori", "D. Belajar dari buku"]'::jsonb, 'B. Belajar sambil melakukan'),
(1, 'Penggolongan usia Pramuka Siaga adalah...', '["A. 7 - 10 tahun", "B. 11 - 15 tahun", "C. 16 - 20 tahun", "D. 21 - 25 tahun"]'::jsonb, 'A. 7 - 10 tahun'),
(1, 'Penggolongan usia Pramuka Penggalang adalah...', '["A. 7 - 10 tahun", "B. 11 - 15 tahun", "C. 16 - 20 tahun", "D. 21 - 25 tahun"]'::jsonb, 'B. 11 - 15 tahun'),
(1, 'Penggolongan usia Pramuka Penegak adalah...', '["A. 7 - 10 tahun", "B. 11 - 15 tahun", "C. 16 - 20 tahun", "D. 21 - 25 tahun"]'::jsonb, 'C. 16 - 20 tahun'),
(1, 'Penggolongan usia Pramuka Pandega adalah...', '["A. 7 - 10 tahun", "B. 11 - 15 tahun", "C. 16 - 20 tahun", "D. 21 - 25 tahun"]'::jsonb, 'D. 21 - 25 tahun'),
(1, 'Kode Kehormatan bagi Pramuka Siaga terdiri dari...', '["A. Trisatya dan Dasadarma", "B. Dwisatya dan Dwidarma", "C. Pancasila", "D. Sumpah Pemuda"]'::jsonb, 'B. Dwisatya dan Dwidarma'),
(1, 'Kode Kehormatan bagi Pramuka Penggalang, Penegak, dan Pandega terdiri dari...', '["A. Dwisatya dan Dwidarma", "B. Trisatya dan Dasadarma", "C. Catur Darma", "D. Panca Darma"]'::jsonb, 'B. Trisatya dan Dasadarma'),
(1, 'Sistem Pendidikan Kepramukaan menggunakan Sistem Among yang digagas oleh...', '["A. Soekarno", "B. Baden Powell", "C. Ki Hajar Dewantara", "D. Sri Sultan HB IX"]'::jsonb, 'C. Ki Hajar Dewantara'),
(1, 'Semboyan Sistem Among di depan memberikan teladan adalah...', '["A. Ing Ngarso Sung Tulodo", "B. Ing Madyo Mangun Karso", "C. Tut Wuri Handayani", "D. Bhinneka Tunggal Ika"]'::jsonb, 'A. Ing Ngarso Sung Tulodo'),
(1, 'Semboyan Sistem Among di tengah membangun kemauan adalah...', '["A. Ing Ngarso Sung Tulodo", "B. Ing Madyo Mangun Karso", "C. Tut Wuri Handayani", "D. Rawe-rawe rantas"]'::jsonb, 'B. Ing Madyo Mangun Karso'),
(1, 'Semboyan Sistem Among di belakang memberikan dorongan adalah...', '["A. Ing Ngarso Sung Tulodo", "B. Ing Madyo Mangun Karso", "C. Tut Wuri Handayani", "D. Jer basuki mawa beya"]'::jsonb, 'C. Tut Wuri Handayani'),
(1, 'Satuan terkecil dalam Pramuka Siaga disebut...', '["A. Regu", "B. Sangga", "C. Barung", "D. Reka"]'::jsonb, 'C. Barung'),
(1, 'Satuan terkecil dalam Pramuka Penggalang disebut...', '["A. Barung", "B. Regu", "C. Sangga", "D. Kelompok"]'::jsonb, 'B. Regu'),
(1, 'Satuan terkecil dalam Pramuka Penegak disebut...', '["A. Reka", "B. Regu", "C. Barung", "D. Sangga"]'::jsonb, 'D. Sangga'),
(1, 'Satuan terkecil dalam Pramuka Pandega disebut...', '["A. Reka", "B. Sangga", "C. Regu", "D. Barung"]'::jsonb, 'A. Reka'),
(1, 'Kumpulan dari beberapa Barung dalam Siaga disebut...', '["A. Pasukan", "B. Perindukan", "C. Ambalan", "D. Racana"]'::jsonb, 'B. Perindukan'),
(1, 'Kumpulan dari beberapa Regu dalam Penggalang disebut...', '["A. Perindukan", "B. Pasukan", "C. Ambalan", "D. Gugus Depan"]'::jsonb, 'B. Pasukan'),
(1, 'Kumpulan dari beberapa Sangga dalam Penegak disebut...', '["A. Ambalan", "B. Racana", "C. Pasukan", "D. Perindukan"]'::jsonb, 'A. Ambalan'),
(1, 'Wadah pembinaan Pramuka Pandega di Perguruan Tinggi disebut...', '["A. Ambalan", "B. Racana", "C. Pasukan", "D. Kwartir"]'::jsonb, 'B. Racana'),
(1, 'Tanda kecakapan dalam kepramukaan dibagi menjadi dua, yaitu...', '["A. TKU dan TKK", "B. TKK dan TKG", "C. TKU dan TKA", "D. TKA dan TKG"]'::jsonb, 'A. TKU dan TKK'),
(1, 'TKU singkatan dari...', '["A. Tanda Kehormatan Umum", "B. Tanda Kecakapan Umum", "C. Tanda Keterampilan Umum", "D. Tanda Kepanduan Umum"]'::jsonb, 'B. Tanda Kecakapan Umum'),
(1, 'TKK singkatan dari...', '["A. Tanda Kecakapan Khusus", "B. Tanda Keterampilan Khusus", "C. Tanda Kehormatan Khusus", "D. Tanda Kesatria Khusus"]'::jsonb, 'A. Tanda Kecakapan Khusus'),
(1, 'Tingkatan TKU pada Pramuka Siaga adalah...', '["A. Ramu, Rakit, Terap", "B. Mula, Bantu, Tata", "C. Bantara, Laksana", "D. Purwa, Madya, Utama"]'::jsonb, 'B. Mula, Bantu, Tata'),
(1, 'Tingkatan TKU pada Pramuka Penggalang adalah...', '["A. Ramu, Rakit, Terap", "B. Mula, Bantu, Tata", "C. Bantara, Laksana", "D. Purwa, Madya, Utama"]'::jsonb, 'A. Ramu, Rakit, Terap'),
(1, 'Tingkatan TKU pada Pramuka Penegak adalah...', '["A. Bantara, Laksana", "B. Ramu, Rakit", "C. Mula, Bantu", "D. Taruna, Dewasa"]'::jsonb, 'A. Bantara, Laksana'),
(1, 'Tingkatan TKK (Tanda Kecakapan Khusus) dibagi menjadi 3 tingkatan, yaitu...', '["A. Mula, Bantu, Tata", "B. Ramu, Rakit, Terap", "C. Purwa, Madya, Utama", "D. Bawah, Menengah, Atas"]'::jsonb, 'C. Purwa, Madya, Utama'),
(1, 'Lambang Gerakan Pramuka Indonesia adalah...', '["A. Tunas Kelapa", "B. Bintang", "C. Padi dan Kapas", "D. Bunga Lily (Fleur-de-lis)"]'::jsonb, 'A. Tunas Kelapa'),
(1, 'Pencipta lambang Tunas Kelapa adalah...', '["A. H. Mutahar", "B. Soenardjo Atmodipuro", "C. C. Simanjuntak", "D. W.R. Supratman"]'::jsonb, 'B. Soenardjo Atmodipuro'),
(1, 'Bentuk lambang Pramuka Internasional (WOSM) adalah...', '["A. Tunas Kelapa", "B. Burung Elang", "C. Bunga Lily (Fleur-de-lis)", "D. Kompas"]'::jsonb, 'C. Bunga Lily (Fleur-de-lis)'),
(1, 'Gerakan Pramuka resmi diperkenalkan kepada rakyat Indonesia pada tanggal...', '["A. 14 Agustus 1961", "B. 20 Mei 1908", "C. 28 Oktober 1928", "D. 17 Agustus 1945"]'::jsonb, 'A. 14 Agustus 1961'),
(1, 'Oleh karena itu, Hari Pramuka di Indonesia diperingati setiap tanggal...', '["A. 14 Agustus", "B. 20 Mei", "C. 1 Juni", "D. 22 Desember"]'::jsonb, 'A. 14 Agustus'),
(1, 'Undang-Undang yang mengatur tentang Gerakan Pramuka saat ini adalah...', '["A. UU No. 20 Tahun 2003", "B. UU No. 12 Tahun 2010", "C. UU No. 14 Tahun 2005", "D. UU No. 40 Tahun 2009"]'::jsonb, 'B. UU No. 12 Tahun 2010'),
(1, 'Motto Gerakan Pramuka adalah...', '["A. Satyaku Kudarmakan, Darmaku Kubaktikan", "B. Berbakti dan Mengabdi", "C. Ikhlas Bakti Bina Bangsa", "D. Suci dalam pikiran, perkataan, dan perbuatan"]'::jsonb, 'A. Satyaku Kudarmakan, Darmaku Kubaktikan'),
(1, 'Tingkatan tertinggi dalam setiap golongan Pramuka yang telah memenuhi syarat pencapaian Garuda disebut...', '["A. Pramuka Utama", "B. Pramuka Teladan", "C. Pramuka Garuda", "D. Pramuka Mandiri"]'::jsonb, 'C. Pramuka Garuda');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(3, 'Nama lengkap Bapak Pandu Dunia adalah...', '["A. Robert Stephenson Smyth Baden-Powell", "B. William Smyth Baden-Powell", "C. George Stephenson Baden-Powell", "D. Robert Arthur Baden-Powell"]'::jsonb, 'A. Robert Stephenson Smyth Baden-Powell'),
(3, 'Baden-Powell lahir di kota...', '["A. Manchester", "B. Liverpool", "C. London", "D. Oxford"]'::jsonb, 'C. London'),
(3, 'Tanggal lahir Baden-Powell adalah...', '["A. 14 Agustus 1857", "B. 22 Februari 1857", "C. 20 Mei 1908", "D. 8 Januari 1857"]'::jsonb, 'B. 22 Februari 1857'),
(3, 'Nama ayah Baden-Powell adalah...', '["A. Prof. Domine Baden-Powell", "B. Admiral W.T. Smyth", "C. Lord George Powell", "D. Sir Arthur Baden"]'::jsonb, 'A. Prof. Domine Baden-Powell'),
(3, 'Profesi ayah Baden-Powell adalah seorang...', '["A. Perwira Angkatan Laut", "B. Guru Besar Geometri di Universitas Oxford", "C. Jenderal Angkatan Darat", "D. Dokter Bedah"]'::jsonb, 'B. Guru Besar Geometri di Universitas Oxford'),
(3, 'Nama ibu dari Baden-Powell adalah...', '["A. Olave St. Clair", "B. Agnes Smyth", "C. Miss Henrietta Grace Smyth", "D. Elizabeth Grace"]'::jsonb, 'C. Miss Henrietta Grace Smyth'),
(3, 'Ayah dari ibu Baden-Powell (kakek dari pihak ibu) adalah seorang laksamana bernama...', '["A. Admiral William T. Smyth", "B. Laksamana Nelson", "C. Admiral John Powell", "D. Laksamana Arthur"]'::jsonb, 'A. Admiral William T. Smyth'),
(3, 'Ayah Baden-Powell meninggal dunia ketika Baden-Powell berusia...', '["A. 3 tahun", "B. 5 tahun", "C. 7 tahun", "D. 10 tahun"]'::jsonb, 'A. 3 tahun'),
(3, 'Julukan Baden-Powell saat bersekolah di Charterhouse School karena kebiasaannya mandi air dingin adalah...', '["A. The Wolf", "B. Bathing Towel", "C. Stevey", "D. Little Robert"]'::jsonb, 'B. Bathing Towel'),
(3, 'Kepala sekolah di Charterhouse yang sangat berpengaruh terhadap pembentukan karakter Baden-Powell adalah...', '["A. Dr. Haig Brown", "B. Dr. William Smyth", "C. Prof. George", "D. Mayor Kenneth"]'::jsonb, 'A. Dr. Haig Brown'),
(3, 'Setelah lulus dari Charterhouse, Baden-Powell mengikuti ujian militer dan lulus kavaleri dengan urutan ke...', '["A. Satu", "B. Dua", "C. Tiga", "D. Empat"]'::jsonb, 'B. Dua'),
(3, 'Pasukan kavaleri yang pertama kali ditempati Baden-Powell di India adalah...', '["A. 1st Infantry", "B. 5th Royal", "C. 13th Hussars", "D. 8th Cavalry"]'::jsonb, 'C. 13th Hussars'),
(3, 'Baden-Powell pertama kali ditugaskan ke India sebagai prajurit muda pada tahun...', '["A. 1876", "B. 1880", "C. 1899", "D. 1900"]'::jsonb, 'A. 1876'),
(3, 'Pangkat pertama Baden-Powell saat bergabung di ketentaraan di India adalah...', '["A. Kapten", "B. Mayor", "C. Pembantu Letnan (Sub-Lieutenant)", "D. Kolonel"]'::jsonb, 'C. Pembantu Letnan (Sub-Lieutenant)'),
(3, 'Suku Zulu, Ashanti, dan Matabele di Afrika memberikan julukan khusus kepada Baden-Powell, yaitu...', '["A. Sang Macan", "B. Impeesa", "C. Mafeking", "D. Bwana"]'::jsonb, 'B. Impeesa'),
(3, 'Arti dari julukan "Impeesa" yang diberikan oleh suku di Afrika adalah...', '["A. Singa yang perkasa", "B. Burung elang yang tajam", "C. Serigala yang tidak pernah tidur", "D. Ksatria pemberani"]'::jsonb, 'C. Serigala yang tidak pernah tidur'),
(3, 'Baden-Powell berhasil mempertahankan sebuah kota dari kepungan bangsa Boer di Afrika Selatan selama 217 hari. Kota tersebut bernama...', '["A. Pretoria", "B. Cape Town", "C. Johannesburg", "D. Mafeking"]'::jsonb, 'D. Mafeking'),
(3, 'Peristiwa pengepungan kota Mafeking terjadi pada tahun...', '["A. 1876 - 1877", "B. 1899 - 1900", "C. 1907 - 1908", "D. 1914 - 1918"]'::jsonb, 'B. 1899 - 1900'),
(3, 'Buku panduan pelacakan militer yang ditulis Baden-Powell dan kelak disukai oleh anak-anak muda Inggris adalah...', '["A. Scouting for Boys", "B. Aids to Scouting", "C. Rovering to Success", "D. The Jungle Book"]'::jsonb, 'B. Aids to Scouting'),
(3, 'Buku "Aids to Scouting" diterbitkan pada tahun...', '["A. 1899", "B. 1907", "C. 1908", "D. 1910"]'::jsonb, 'A. 1899'),
(3, 'Perkemahan percobaan kepanduan pertama kali diadakan oleh Baden-Powell di sebuah pulau bernama...', '["A. Pulau Gilwell", "B. Pulau Brownsea", "C. Pulau Wight", "D. Pulau Britania"]'::jsonb, 'B. Pulau Brownsea'),
(3, 'Perkemahan di Pulau Brownsea yang menjadi tonggak sejarah kepramukaan dilaksanakan pada tahun...', '["A. 1899", "B. 1907", "C. 1908", "D. 1920"]'::jsonb, 'B. 1907'),
(3, 'Berapa jumlah anak laki-laki yang mengikuti perkemahan percobaan di Pulau Brownsea?', '["A. 15 anak", "B. 20 anak", "C. 22 anak", "D. 30 anak"]'::jsonb, 'C. 22 anak'),
(3, 'Teman tentara yang membantu Baden-Powell mengurus perkemahan di Pulau Brownsea adalah...', '["A. Mayor Kenneth McLaren", "B. Arthur Pearson", "C. William Smyth", "D. King Edward VII"]'::jsonb, 'A. Mayor Kenneth McLaren'),
(3, 'Buku panduan utama yang menjadi cikal bakal berdirinya gerakan kepanduan dunia adalah...', '["A. Aids to Scouting", "B. Rovering to Success", "C. Scouting for Boys", "D. Wolf Cub''s Handbook"]'::jsonb, 'C. Scouting for Boys'),
(3, 'Buku "Scouting for Boys" karya Baden-Powell pertama kali diterbitkan pada tahun...', '["A. 1907", "B. 1908", "C. 1910", "D. 1912"]'::jsonb, 'B. 1908'),
(3, 'Organisasi kepanduan putri (Girl Guides) pertama kali dibentuk dengan bantuan adik perempuan Baden-Powell yang bernama...', '["A. Olave Baden-Powell", "B. Henrietta Grace", "C. Agnes Baden-Powell", "D. Jessie Baden-Powell"]'::jsonb, 'C. Agnes Baden-Powell'),
(3, 'Organisasi Girl Guides (Kepanduan Putri) dirintis pada tahun...', '["A. 1908", "B. 1910", "C. 1912", "D. 1916"]'::jsonb, 'B. 1910'),
(3, 'Kepanduan untuk golongan anak-anak (Siaga/Wolf Cub) didirikan oleh Baden-Powell pada tahun...', '["A. 1908", "B. 1912", "C. 1916", "D. 1920"]'::jsonb, 'C. 1916'),
(3, 'Buku panduan yang digunakan Baden-Powell untuk menginspirasi golongan Siaga (Wolf Cub) adalah...', '["A. Scouting for Boys", "B. The Jungle Book", "C. Aids to Scouting", "D. Rovering to Success"]'::jsonb, 'B. The Jungle Book'),
(3, 'Penulis buku "The Jungle Book" yang menginspirasi pembentukan golongan Siaga adalah...', '["A. Rudyard Kipling", "B. Arthur Conan Doyle", "C. William Shakespeare", "D. J.K. Rowling"]'::jsonb, 'A. Rudyard Kipling'),
(3, 'Kepanduan untuk golongan pemuda (Penegak/Rover Scout) dibentuk pada tahun...', '["A. 1916", "B. 1918", "C. 1920", "D. 1922"]'::jsonb, 'B. 1918'),
(3, 'Buku panduan untuk Rover Scout yang ditulis oleh Baden-Powell pada tahun 1922 berjudul...', '["A. The Jungle Book", "B. Aids to Scouting", "C. Rovering to Success", "D. Scouting for Boys"]'::jsonb, 'C. Rovering to Success'),
(3, 'Jambore Kepanduan Dunia pertama kali diadakan di gedung...', '["A. Olympia Hall", "B. Wembley Stadium", "C. Royal Albert Hall", "D. Gilwell Park"]'::jsonb, 'A. Olympia Hall'),
(3, 'Jambore Dunia pertama diadakan di kota London pada tahun...', '["A. 1918", "B. 1920", "C. 1922", "D. 1924"]'::jsonb, 'B. 1920'),
(3, 'Pada malam terakhir Jambore Dunia pertama, Baden-Powell secara resmi diangkat menjadi...', '["A. Jenderal Pandu", "B. Raja Pandu", "C. Bapak Pandu Dunia (Chief Scout of the World)", "D. Presiden WOSM"]'::jsonb, 'C. Bapak Pandu Dunia (Chief Scout of the World)'),
(3, 'Gelar kehormatan "Lord" (Baron) dianugerahkan kepada Baden-Powell oleh Raja George V pada tahun...', '["A. 1920", "B. 1925", "C. 1929", "D. 1937"]'::jsonb, 'C. 1929'),
(3, 'Nama istri Baden-Powell yang kelak menjadi Chief Guide of the World adalah...', '["A. Agnes Smyth", "B. Olave St. Clair Soames", "C. Henrietta Grace", "D. Elizabeth Baden"]'::jsonb, 'B. Olave St. Clair Soames'),
(3, 'Baden-Powell pensiun dari dinas kemiliteran Inggris dengan pangkat terakhir...', '["A. Mayor Jenderal", "B. Letnan Jenderal", "C. Jenderal Penuh", "D. Marsekal"]'::jsonb, 'B. Letnan Jenderal'),
(3, 'Raja Inggris yang menyarankan Baden-Powell untuk pensiun dari militer agar bisa membesarkan Gerakan Kepanduan adalah...', '["A. Raja George V", "B. Raja George VI", "C. Raja Edward VII", "D. Ratu Victoria"]'::jsonb, 'C. Raja Edward VII'),
(3, 'Pada tahun 1919, W. de Bois Maclaren menyumbangkan sebidang tanah untuk pusat pelatihan pembina pramuka yang diberi nama...', '["A. Brownsea Island", "B. Mafeking Camp", "C. Gilwell Park", "D. Olympia Hall"]'::jsonb, 'C. Gilwell Park'),
(3, 'Kursus Pembina Pramuka (Wood Badge) pertama kali diselenggarakan di Gilwell Park pada tahun...', '["A. 1916", "B. 1919", "C. 1920", "D. 1922"]'::jsonb, 'B. 1919'),
(3, 'Kalung manik-manik kayu (Wood Badge) berasal dari kalung pimpinan suku Afrika yang pernah dikalahkan oleh Baden-Powell, bernama...', '["A. Zulu", "B. Dinizulu", "C. Ashanti", "D. Matabele"]'::jsonb, 'B. Dinizulu'),
(3, 'Simbol dari pusat pelatihan pembina Gilwell Park adalah...', '["A. Bunga Lily", "B. Tunas Kelapa", "C. Kapak menancap di balok kayu", "D. Serigala"]'::jsonb, 'C. Kapak menancap di balok kayu'),
(3, 'Baden-Powell menghabiskan masa tuanya dan meninggal dunia di negara...', '["A. Inggris", "B. Afrika Selatan", "C. India", "D. Kenya"]'::jsonb, 'D. Kenya'),
(3, 'Baden-Powell meninggal dunia pada tanggal...', '["A. 8 Januari 1941", "B. 22 Februari 1941", "C. 14 Agustus 1941", "D. 30 Oktober 1941"]'::jsonb, 'A. 8 Januari 1941'),
(3, 'Baden-Powell dimakamkan di pemakaman St. Peter, di kota...', '["A. London", "B. Cape Town", "C. Nyeri", "D. Nairobi"]'::jsonb, 'C. Nyeri'),
(3, 'Usia Baden-Powell saat meninggal dunia adalah...', '["A. 73 tahun", "B. 80 tahun", "C. 83 tahun", "D. 90 tahun"]'::jsonb, 'C. 83 tahun'),
(3, 'Pada batu nisan makam Baden-Powell terdapat tanda jejak kepanduan berupa lingkaran dengan titik di tengah yang memiliki arti...', '["A. Saya telah pulang", "B. Bahaya di depan", "C. Jalan terus", "D. Tunggu di sini"]'::jsonb, 'A. Saya telah pulang'),
(3, 'Organisasi kepanduan dunia saat ini bernaung di bawah organisasi bernama WOSM, singkatan dari...', '["A. World Organization of Scout Members", "B. World Organization of the Scout Movement", "C. World Order of Scout Movement", "D. World Organization of Scouting Men"]'::jsonb, 'B. World Organization of the Scout Movement');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(5, 'Bab 5 dalam buku referensi Boyman secara khusus membahas rangkuman dari buku legendaris karya Baden-Powell yang berjudul...', '["A. Rovering to Success", "B. Scouting for Boys", "C. Aids to Scouting", "D. The Wolf Cub''s Handbook"]'::jsonb, 'B. Scouting for Boys'),
(5, 'Buku Scouting for Boys pada dasarnya dibagi ke dalam beberapa sub-bab yang disebut dengan istilah...', '["A. Panduan Rimba", "B. Sesi Petualangan", "C. Cerita Api Unggun", "D. Kisah Penjelajah"]'::jsonb, 'C. Cerita Api Unggun'),
(5, 'Ada berapa total Cerita Api Unggun (Campfire Yarns) yang menjadi susunan utama materi Scouting for Boys?', '["A. 15 Cerita", "B. 21 Cerita", "C. 24 Cerita", "D. 26 Cerita"]'::jsonb, 'D. 26 Cerita'),
(5, 'Cerita Api Unggun ke-1 membahas sejarah tentang pasukan anak laki-laki di Afrika yang menjadi inspirasi kepanduan, yang disebut...', '["A. Mafeking Cadet Corps", "B. Brownsea Troops", "C. Boy Scouts of Africa", "D. The Wolf Cubs"]'::jsonb, 'A. Mafeking Cadet Corps'),
(5, 'Pemimpin pasukan anak-anak pada masa pengepungan Mafeking tersebut adalah...', '["A. Mayor Kenneth", "B. Lord Edward Cecil", "C. Jenderal Kitchener", "D. Arthur Pearson"]'::jsonb, 'B. Lord Edward Cecil'),
(5, 'Baden-Powell menyadari kehebatan pasukan anak-anak di Mafeking yang kemudian menjadi cikal bakal pentingnya peran kaum muda. Pengepungan kota Mafeking terjadi di negara...', '["A. Afrika Selatan", "B. Kenya", "C. India", "D. Inggris"]'::jsonb, 'A. Afrika Selatan'),
(5, 'Cerita Api Unggun ke-4 membahas inti dari sistem kepramukaan yang membagi anggota ke dalam kelompok kecil, disebut dengan...', '["A. Sistem Kelompok", "B. Sistem Pasukan", "C. Sistem Regu (Patrol System)", "D. Sistem Ambalan"]'::jsonb, 'C. Sistem Regu (Patrol System)'),
(5, 'Menurut gagasan awal Baden-Powell, jumlah anggota yang ideal dalam satu regu pramuka (patrol) adalah...', '["A. 3 sampai 5 orang", "B. 6 sampai 8 orang", "C. 10 sampai 12 orang", "D. 15 sampai 20 orang"]'::jsonb, 'B. 6 sampai 8 orang'),
(5, 'Sebutan untuk pemimpin regu dalam bahasa Inggris yang dicetuskan oleh Baden-Powell adalah...', '["A. Scout Leader", "B. Chief Scout", "C. Troop Leader", "D. Patrol Leader"]'::jsonb, 'D. Patrol Leader'),
(5, 'Cerita Api Unggun ke-8 membahas tentang keterampilan membuat bangunan darurat menggunakan kayu dan tali, yang dalam istilah kepramukaan disebut...', '["A. Pionering / Kepeloporan", "B. Navigasi Darat", "C. Bivak", "D. Survival"]'::jsonb, 'A. Pionering / Kepeloporan'),
(5, 'Simpul dasar dalam pionering yang berguna untuk menyambung dua utas tali yang sama besar dan tidak licin adalah...', '["A. Simpul Mati (Reef Knot)", "B. Simpul Hidup", "C. Simpul Anyam", "D. Simpul Delapan"]'::jsonb, 'A. Simpul Mati (Reef Knot)'),
(5, 'Simpul yang berguna untuk mengikat leher binatang agar tidak tercekik, serta sering menjadi simpul dasar penyelamatan adalah...', '["A. Simpul Pangkal", "B. Simpul Tarik", "C. Simpul Tiang (Bowline)", "D. Simpul Jangkar"]'::jsonb, 'C. Simpul Tiang (Bowline)'),
(5, 'Simpul yang paling sering digunakan untuk memulai dan mengakhiri sebuah ikatan pada tongkat pionering adalah...', '["A. Simpul Mati", "B. Simpul Pangkal (Clove Hitch)", "C. Simpul Kembar", "D. Simpul Ujung Tali"]'::jsonb, 'B. Simpul Pangkal (Clove Hitch)'),
(5, 'Simpul yang digunakan untuk menyambung dua utas tali yang ukurannya tidak sama besar dan dalam keadaan kering adalah...', '["A. Simpul Tarik", "B. Simpul Erat", "C. Simpul Nelayan", "D. Simpul Anyam (Sheet Bend)"]'::jsonb, 'D. Simpul Anyam (Sheet Bend)'),
(5, 'Ikatan yang digunakan untuk menggabungkan dua buah tongkat yang bersilangan tegak lurus (membentuk sudut 90 derajat) adalah...', '["A. Ikatan Palang (Square Lashing)", "B. Ikatan Silang (Diagonal Lashing)", "C. Ikatan Canggah", "D. Ikatan Kaki Tiga"]'::jsonb, 'A. Ikatan Palang (Square Lashing)'),
(5, 'Cerita Api Unggun ke-9 membahas mengenai kehidupan di alam terbuka, yaitu rutinitas...', '["A. Penjelajahan", "B. Perkemahan (Camping)", "C. Pendakian", "D. Susur Sungai"]'::jsonb, 'B. Perkemahan (Camping)'),
(5, 'Hal yang paling utama dan penting untuk diperhatikan saat memilih lokasi untuk mendirikan tenda perkemahan adalah...', '["A. Dekat dengan jalan raya besar", "B. Pemandangan yang indah", "C. Dekat sumber air bersih dan aman dari bahaya alam", "D. Berada di tanah yang landai dan berpasir"]'::jsonb, 'C. Dekat sumber air bersih dan aman dari bahaya alam'),
(5, 'Cerita Api Unggun ke-10 memberikan panduan teknis yang sangat dibutuhkan regu mandiri, yaitu tentang...', '["A. Masakan di Perkemahan (Camp Cooking)", "B. Pertolongan Pertama", "C. Navigasi Malam", "D. Tanda Bahaya"]'::jsonb, 'A. Masakan di Perkemahan (Camp Cooking)'),
(5, 'Salah satu makanan khas perkemahan ala Baden-Powell, di mana adonan tepung dililitkan pada sebatang kayu lalu dipanggang di atas bara api, disebut...', '["A. Roti Pandu", "B. Roti Lilit (Twist)", "C. Kue Api", "D. Biskuit Darurat"]'::jsonb, 'B. Roti Lilit (Twist)'),
(5, 'Cerita Api Unggun ke-11 dan 12 mengajarkan keterampilan mengasah kepekaan mata di alam terbuka, berupa...', '["A. Semboyan Isyarat", "B. Pengamatan Bintang", "C. Mencari dan Mengikuti Jejak (Tracking)", "D. Mengukur Ketinggian Pohon"]'::jsonb, 'C. Mencari dan Mengikuti Jejak (Tracking)'),
(5, 'Saat sedang mengikuti jejak di alam bebas, seorang Pramuka dianjurkan untuk berjalan dengan cara...', '["A. Berlari cepat agar tidak kehilangan jejak", "B. Membawa senjata tajam bersiaga penuh", "C. Sambil bernyanyi untuk menghilangkan rasa takut", "D. Tenang sambil memperhatikan keadaan tanah dan sekelilingnya"]'::jsonb, 'D. Tenang sambil memperhatikan keadaan tanah dan sekelilingnya'),
(5, 'Dalam sandi jejak Pramuka, susunan batu yang ditumpuk menjadi tiga bagian dan ditambahkan satu batu kecil di sebelah kanan memiliki arti...', '["A. Jalan ke arah kanan", "B. Ada air di sebelah kanan", "C. Rintangan di depan", "D. Tempat berkemah di kanan"]'::jsonb, 'A. Jalan ke arah kanan'),
(5, 'Sebuah lingkaran yang digambar di tanah dengan titik di tengahnya merupakan tanda jejak kepanduan yang berarti...', '["A. Bahaya, jangan melintas", "B. Air beracun", "C. Saya telah pulang / Kembali ke perkemahan", "D. Tunggu di sini"]'::jsonb, 'C. Saya telah pulang / Kembali ke perkemahan'),
(5, 'Cerita Api Unggun ke-13 menuntut seorang pandu untuk memiliki kemampuan observasi dan deduksi. Tokoh detektif fiksi yang sering dijadikan contoh oleh Baden-Powell untuk hal ini adalah...', '["A. Hercule Poirot", "B. Sherlock Holmes", "C. James Bond", "D. Inspektur Gadget"]'::jsonb, 'B. Sherlock Holmes'),
(5, 'Cerita Api Unggun ke-14 berjudul "Menyembunyikan Diri - Mengendap" (Stalking). Mengendap sangat berguna di alam bebas untuk...', '["A. Mendekati dan mengamati hewan liar tanpa disadari oleh hewan tersebut", "B. Menyerang musuh secara diam-diam", "C. Bersembunyi dari tugas perkemahan", "D. Bermain petak umpet dengan regu lain"]'::jsonb, 'A. Mendekati dan mengamati hewan liar tanpa disadari oleh hewan tersebut'),
(5, 'Aturan utama yang harus diperhatikan seorang Pramuka saat sedang mengendap mendekati target di alam liar adalah...', '["A. Memakai wewangian agar hewan tidak curiga", "B. Bergerak serah dengan hembusan angin", "C. Bergerak berlawanan arah dengan hembusan angin", "D. Membawa makanan untuk memancing hewan"]'::jsonb, 'C. Bergerak berlawanan arah dengan hembusan angin'),
(5, 'Cerita Api Unggun ke-15 dan 16 membahas apresiasi terhadap lingkungan hidup, yakni tentang pengetahuan...', '["A. Batuan dan Mineral", "B. Binatang dan Tumbuh-tumbuhan", "C. Cuaca dan Iklim", "D. Mata Air dan Sungai"]'::jsonb, 'B. Binatang dan Tumbuh-tumbuhan'),
(5, 'Prinsip konservasi dalam kepanduan menyatakan bahwa seorang Pramuka dilarang keras membunuh binatang apa pun, KECUALI...', '["A. Binatang tersebut memiliki bulu yang berharga", "B. Untuk dijadikan koleksi awetan", "C. Saat sedang mengikuti perlombaan berburu", "D. Ketika terancam bahaya atau terpaksa untuk bertahan hidup/makan"]'::jsonb, 'D. Ketika terancam bahaya atau terpaksa untuk bertahan hidup/makan'),
(5, 'Pengetahuan seorang Pramuka dalam mengenali berbagai jenis pohon liar, dedaunan, dan akar yang bisa dimakan sangat menunjang kemampuannya dalam bidang...', '["A. Survival (Bertahan Hidup)", "B. Navigasi Darat", "C. Pionering", "D. Pertolongan Pertama"]'::jsonb, 'A. Survival (Bertahan Hidup)'),
(5, 'Cerita Api Unggun ke-17 berjudul "Bagaimana Supaya Kuat", yang memberikan instruksi agar kaum muda terbiasa menjaga...', '["A. Ketahanan mental saat di-bully", "B. Kekuatan finansial di masa depan", "C. Kesehatan fisik dan kebugaran tubuh", "D. Kecerdasan otak dan logika"]'::jsonb, 'C. Kesehatan fisik dan kebugaran tubuh'),
(5, 'Untuk melatih kebugaran tubuh setiap hari, Baden-Powell menyarankan rutinitas senam pagi yang dikenal sebagai...', '["A. Senam Kesegaran Jasmani (SKJ)", "B. 6 Latihan Fisik BP (BP Exercises)", "C. Senam Pagi Indonesia", "D. Senam Aerobik"]'::jsonb, 'B. 6 Latihan Fisik BP (BP Exercises)'),
(5, 'Cerita Api Unggun ke-18 dan 19 mengulas tentang kebiasaan yang menyehatkan serta pencegahan penyakit. Baden-Powell sangat mewajibkan pandu bernapas dengan benar melalui...', '["A. Hidung, bukan mulut", "B. Mulut secara perlahan", "C. Dada secara dalam", "D. Perut bagian bawah"]'::jsonb, 'A. Hidung, bukan mulut'),
(5, 'Penyakit yang sering menyerang anggota perkemahan akibat meminum air mentah atau lingkungan perkemahan yang kurang bersih (sanitasi buruk) adalah...', '["A. Tifus dan Malaria", "B. Demam Berdarah", "C. Flu dan Batuk", "D. Diare dan Disentri"]'::jsonb, 'D. Diare dan Disentri'),
(5, 'Cerita Api Unggun ke-20 bertemakan "Sikap Kesatria" (Chivalry). Inspirasi utama Baden-Powell dalam membentuk karakter Pramuka ini berasal dari legenda pahlawan kuno, yaitu...', '["A. Kesatria Templar", "B. Kesatria Meja Bundar (Knights of the Round Table)", "C. Pasukan Spartan", "D. Samurai Jepang"]'::jsonb, 'B. Kesatria Meja Bundar (Knights of the Round Table)'),
(5, 'Raja legendaris Inggris yang memimpin para kesatria mulia dalam perumpamaan Baden-Powell tersebut adalah...', '["A. Raja Richard", "B. Raja George", "C. Raja Arthur", "D. Raja Edward"]'::jsonb, 'C. Raja Arthur'),
(5, 'Tokoh orang suci pelindung Inggris (Patron Saint) yang juga dijadikan sebagai pelindung simbolis kaum pandu di seluruh dunia karena keberaniannya membunuh naga adalah...', '["A. Santo George (St. George)", "B. Santo Petrus", "C. Santo Paulus", "D. Santo Andreas"]'::jsonb, 'A. Santo George (St. George)'),
(5, 'Hari peringatan St. George, yang sering dirayakan secara internasional oleh anggota Pramuka sebagai ajang pembaruan Janji Pramuka, jatuh pada tanggal...', '["A. 22 Februari", "B. 23 April", "C. 14 Agustus", "D. 1 Juni"]'::jsonb, 'B. 23 April'),
(5, 'Cerita Api Unggun ke-21 menekankan pada konsep utama watak yang membuat seorang pandu dihormati, yaitu...', '["A. Keberanian", "B. Kecerdasan", "C. Disiplin", "D. Kecekatan"]'::jsonb, 'C. Disiplin'),
(5, 'Ciri sejati dari kedisiplinan seorang Pramuka saat menerima instruksi dari pimpinannya adalah...', '["A. Mematuhi perintah dan aturan dengan sigap tanpa mengeluh", "B. Menanyakan alasan setiap perintah terlebih dahulu", "C. Melaksanakan perintah hanya jika dirasa masuk akal", "D. Mengerjakan perintah dengan pelan agar teliti"]'::jsonb, 'A. Mematuhi perintah dan aturan dengan sigap tanpa mengeluh'),
(5, 'Cerita Api Unggun ke-22 berjudul "Memperbaiki Diri". Hal ini mengajarkan filosofi bahwa seorang pandu sejati harus...', '["A. Sering mengganti seragamnya agar selalu rapi", "B. Mencari kelemahan orang lain untuk diperbaiki", "C. Memperbaiki peralatan perkemahan yang rusak", "D. Terus mengasah keahlian dan akhlaknya secara mandiri agar hidupnya lebih berguna"]'::jsonb, 'D. Terus mengasah keahlian dan akhlaknya secara mandiri agar hidupnya lebih berguna'),
(5, 'Cerita Api Unggun ke-23 dan 24 membahas tentang keterampilan vital yang harus dimiliki setiap Pramuka jika terjadi insiden darurat, yakni tentang...', '["A. Evakuasi Bencana Alam", "B. Menyelamatkan Hidup dan Penanganan Kecelakaan (P3K)", "C. Membuat Pemancar Radio Darurat", "D. Teknik Berenang Jarak Jauh"]'::jsonb, 'B. Menyelamatkan Hidup dan Penanganan Kecelakaan (P3K)'),
(5, 'Kaidah terpenting dan pertama kali yang harus dikuasai secara mental saat seorang Pramuka menghadapi situasi kecelakaan parah adalah...', '["A. Tetap tenang dan tidak panik", "B. Langsung memindahkan korban", "C. Berteriak meminta tolong sekeras mungkin", "D. Mengobati luka dengan obat apa saja"]'::jsonb, 'A. Tetap tenang dan tidak panik'),
(5, 'Apabila menemui korban yang mengalami pendarahan hebat (luka terbuka memancar), tindakan Pertolongan Pertama yang paling efektif dilakukan adalah...', '["A. Memberikan korban air minum yang banyak", "B. Mencuci luka dengan air sungai mengalir", "C. Melakukan tekanan langsung pada area luka / balut tekan", "D. Mengoleskan salep antibiotik di atas luka"]'::jsonb, 'C. Melakukan tekanan langsung pada area luka / balut tekan'),
(5, 'Jika pakaian yang dikenakan oleh seseorang tiba-tiba tersambar api dan terbakar, tindakan penyelematan yang paling tepat diinstruksikan oleh Pramuka adalah...', '["A. Menyuruhnya berlari mencari air", "B. Menyuruhnya berguling-guling di tanah atau membungkusnya rapat dengan selimut tebal", "C. Mengipasi badannya agar api cepat padam", "D. Menyemprotkan cairan alkohol"]'::jsonb, 'B. Menyuruhnya berguling-guling di tanah atau membungkusnya rapat dengan selimut tebal'),
(5, 'Cerita Api Unggun ke-25 mengingatkan tentang tujuan mulia kehadiran gerakan Pramuka dalam masyarakat, yaitu kewajiban untuk...', '["A. Menjaga keamanan desa", "B. Mengatur lalu lintas jalan", "C. Menjadi tentara cadangan", "D. Menolong orang lain di setiap kesempatan"]'::jsonb, 'D. Menolong orang lain di setiap kesempatan'),
(5, 'Sebuah tradisi pandu yang diajarkan oleh Baden-Powell untuk melakukan setidaknya satu kebaikan kecil setiap harinya tanpa mengharap imbalan disebut dengan istilah...', '["A. Good Turn (Berbuat Kebaikan)", "B. Daily Duty (Tugas Harian)", "C. Charity Work (Amal)", "D. Boy Scout Magic"]'::jsonb, 'A. Good Turn (Berbuat Kebaikan)'),
(5, 'Cerita Api Unggun ke-26, yang menjadi bab pamungkas dalam materi buku Scouting for Boys, secara umum membahas tentang sikap tanggung jawab bermasyarakat, yakni...', '["A. Demokrasi (Democracy)", "B. Kewarganegaraan (Citizenship)", "C. Kepemimpinan (Leadership)", "D. Kemandirian (Independence)"]'::jsonb, 'B. Kewarganegaraan (Citizenship)'),
(5, 'Inti dari jiwa kewarganegaraan seorang Pramuka adalah kemauannya untuk memahami sejarah, pemerintahan, dan hukum bangsanya, agar kelak ia menjadi...', '["A. Politikus yang handal", "B. Pekerja yang kaya raya", "C. Warga negara yang aktif dan bermanfaat bagi negaranya", "D. Pejabat militer"]'::jsonb, 'C. Warga negara yang aktif dan bermanfaat bagi negaranya'),
(5, 'Semboyan kepanduan utama yang diperkenalkan Baden-Powell dalam buku ini, yang wajib dipraktikkan baik dalam kesiapan fisik maupun mental oleh pandu di seluruh dunia adalah...', '["A. Be Prepared (Selalu Siap)", "B. Do Your Best (Lakukan yang Terbaik)", "C. Be Brave (Pemberani)", "D. Semper Fidelis (Selalu Setia)"]'::jsonb, 'A. Be Prepared (Selalu Siap)'),
(5, 'Pesan moral secara keseluruhan dari Scouting for Boys yang tercantum di Bab 5 Boyman adalah membentuk remaja agar tidak hanya menjadi sosok petualang alam bebas, tetapi juga menjadi...', '["A. Atlet olahraga yang profesional", "B. Ilmuwan yang ahli flora dan fauna", "C. Prajurit tempur di garis depan", "D. Pria yang bertanggung jawab, mandiri, dan berkarakter mulia"]'::jsonb, 'D. Pria yang bertanggung jawab, mandiri, dan berkarakter mulia');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(9, 'Fungsi utama dari Tanda Pengenal dalam Gerakan Pramuka adalah sebagai...', '["A. Perhiasan seragam agar menarik", "B. Pembeda kasta antar anggota", "C. Alat pendidikan, tanda pengenal, dan pengakuan sah", "D. Pelengkap mode pakaian lapangan"]'::jsonb, 'C. Alat pendidikan, tanda pengenal, dan pengakuan sah'),
(9, 'Berdasarkan macamnya, Tanda Pengenal Gerakan Pramuka dibagi menjadi berapa kelompok?', '["A. 3 kelompok", "B. 4 kelompok", "C. 5 kelompok", "D. 6 kelompok"]'::jsonb, 'C. 5 kelompok'),
(9, 'Kelima macam Tanda Pengenal Gerakan Pramuka tersebut adalah...', '["A. Umum, Khusus, Cabang, Daerah, Nasional", "B. Umum, Satuan, Jabatan, Kecakapan, Kehormatan", "C. Utama, Madya, Purwa, Bantu, Tata", "D. Siaga, Penggalang, Penegak, Pandega, Pembina"]'::jsonb, 'B. Umum, Satuan, Jabatan, Kecakapan, Kehormatan'),
(9, 'Tanda yang dipakai secara umum oleh semua anggota Gerakan Pramuka yang telah dilantik disebut...', '["A. Tanda Satuan", "B. Tanda Jabatan", "C. Tanda Umum", "D. Tanda Kehormatan"]'::jsonb, 'C. Tanda Umum'),
(9, 'Berikut ini yang termasuk dalam kelompok Tanda Umum adalah...', '["A. Tanda Regu dan Tanda Sangga", "B. Tanda Kecakapan Umum (TKU) dan TKK", "C. Tanda Pelantikan, Setangan Leher, dan Tutup Kepala", "D. Tanda Pemimpin Regu dan Pratama"]'::jsonb, 'C. Tanda Pelantikan, Setangan Leher, dan Tutup Kepala'),
(9, 'Warna utama pada setangan leher (kacu) Pramuka Indonesia adalah...', '["A. Coklat tua dan coklat muda", "B. Merah dan Putih", "C. Merah dan Hitam", "D. Kuning dan Hijau"]'::jsonb, 'B. Merah dan Putih'),
(9, 'Tanda Pandu Dunia (WOSM) berwarna dasar ungu dengan lambang bunga lily berwarna putih, diletakkan di...', '["A. Dada sebelah kiri", "B. Dada sebelah kanan (di atas papan nama)", "C. Lengan sebelah kanan", "D. Lengan sebelah kiri"]'::jsonb, 'B. Dada sebelah kanan (di atas papan nama)'),
(9, 'Bentuk Tanda Pelantikan untuk anggota Pramuka putra adalah...', '["A. Bulat", "B. Persegi panjang", "C. Segitiga", "D. Belah ketupat (segi empat silang)"]'::jsonb, 'D. Belah ketupat (segi empat silang)'),
(9, 'Bentuk Tanda Pelantikan untuk anggota Pramuka putri adalah...', '["A. Bulat", "B. Persegi panjang", "C. Segitiga", "D. Belah ketupat"]'::jsonb, 'A. Bulat'),
(9, 'Tanda Pelantikan pada seragam Pramuka putra dipasang di...', '["A. Saku dada kiri", "B. Saku dada kanan", "C. Kerah baju kanan", "D. Kerah baju kiri"]'::jsonb, 'A. Saku dada kiri'),
(9, 'Tanda Pelantikan pada seragam Pramuka putri dipasang di...', '["A. Saku dada kiri", "B. Saku dada kanan", "C. Kerah baju kiri", "D. Kerah baju kanan"]'::jsonb, 'C. Kerah baju kiri'),
(9, 'Tanda Tutup Kepala (Baret) untuk Pramuka Penggalang putra berwarna dasar...', '["A. Hijau", "B. Merah", "C. Kuning", "D. Coklat"]'::jsonb, 'B. Merah'),
(9, 'Tanda Tutup Kepala untuk Pramuka Siaga putra berwarna dasar...', '["A. Hijau", "B. Merah", "C. Kuning", "D. Coklat"]'::jsonb, 'A. Hijau'),
(9, 'Tanda Tutup Kepala untuk Pramuka Penegak putra berwarna dasar...', '["A. Kuning", "B. Merah", "C. Hijau", "D. Coklat"]'::jsonb, 'A. Kuning'),
(9, 'Tanda Tutup Kepala untuk Pramuka Pandega putra berwarna dasar...', '["A. Merah", "B. Kuning", "C. Coklat", "D. Hitam"]'::jsonb, 'C. Coklat'),
(9, 'Tanda pengenal yang menunjukkan tempat/wilayah seorang Pramuka bergabung disebut...', '["A. Tanda Jabatan", "B. Tanda Umum", "C. Tanda Kehormatan", "D. Tanda Satuan"]'::jsonb, 'D. Tanda Satuan'),
(9, 'Pita wilayah (lokasi) kwartir cabang dan lambang/badge daerah dipasang pada seragam Pramuka di bagian...', '["A. Lengan kanan", "B. Lengan kiri", "C. Dada kanan", "D. Dada kiri"]'::jsonb, 'A. Lengan kanan'),
(9, 'Pita nomor Gugus Depan (Gudep) putra memiliki nomor berakhiran...', '["A. Genap", "B. Ganjil", "C. Angka nol", "D. Huruf"]'::jsonb, 'B. Ganjil'),
(9, 'Pita nomor Gugus Depan (Gudep) putri memiliki nomor berakhiran...', '["A. Genap", "B. Ganjil", "C. Angka nol", "D. Huruf"]'::jsonb, 'A. Genap'),
(9, 'Tanda Barung pada Pramuka Siaga berbentuk...', '["A. Persegi", "B. Segitiga sama sisi", "C. Lingkaran", "D. Belah ketupat"]'::jsonb, 'B. Segitiga sama sisi'),
(9, 'Tanda Regu pada Pramuka Penggalang berbentuk persegi empat dengan gambar...', '["A. Bunga", "B. Bintang", "C. Siluet Binatang (Putra) dan Bunga (Putri)", "D. Senjata tradisional"]'::jsonb, 'C. Siluet Binatang (Putra) dan Bunga (Putri)'),
(9, 'Tanda Sangga pada Pramuka Penegak berbentuk bujur sangkar (persegi empat) dengan gambar yang melambangkan...', '["A. Flora dan Fauna", "B. Fase perjuangan bangsa (Perintis, Pencoba, dll)", "C. Senjata", "D. Pahlawan Nasional"]'::jsonb, 'B. Fase perjuangan bangsa (Perintis, Pencoba, dll)'),
(9, 'Tanda Satuan Karya (Saka) dikenakan oleh Pramuka Penegak dan Pandega pada seragam di bagian...', '["A. Lengan kiri", "B. Lengan kanan", "C. Dada kiri", "D. Dada kanan"]'::jsonb, 'A. Lengan kiri'),
(9, 'Tanda pengenal yang menunjukkan wewenang, tanggung jawab, dan hak seseorang dalam memimpin satuan Pramuka disebut...', '["A. Tanda Satuan", "B. Tanda Jabatan", "C. Tanda Kecakapan", "D. Tanda Kehormatan"]'::jsonb, 'B. Tanda Jabatan'),
(9, 'Tanda Jabatan Pemimpin Regu Penggalang berbentuk balok melintang yang dijahit di saku dada sebelah kanan. Jumlah balok untuk Pemimpin Regu adalah...', '["A. 1 balok", "B. 2 balok", "C. 3 balok", "D. 4 balok"]'::jsonb, 'B. 2 balok'),
(9, 'Jumlah balok untuk Wakil Pemimpin Regu Penggalang adalah...', '["A. 1 balok", "B. 2 balok", "C. 3 balok", "D. Tidak memakai balok"]'::jsonb, 'A. 1 balok'),
(9, 'Pemimpin Regu Utama yang memimpin seluruh pasukan Penggalang disebut Pratama. Tanda jabatannya berupa balok merah berjumlah...', '["A. 1 balok", "B. 2 balok", "C. 3 balok", "D. 4 balok"]'::jsonb, 'C. 3 balok'),
(9, 'Pemimpin Barung Utama pada Pramuka Siaga disebut...', '["A. Pratama", "B. Pradana", "C. Sulung", "D. Ketua Adat"]'::jsonb, 'C. Sulung'),
(9, 'Pemimpin Sangga Utama pada Pramuka Penegak yang memimpin Ambalan disebut...', '["A. Pradana", "B. Pratama", "C. Sulung", "D. Juru Adat"]'::jsonb, 'A. Pradana'),
(9, 'Warna dasar Tanda Jabatan Dewan Ambalan Penegak adalah...', '["A. Hijau", "B. Merah", "C. Kuning", "D. Coklat"]'::jsonb, 'C. Kuning'),
(9, 'Tanda Kecakapan Umum (TKU) Pramuka Siaga dipasang pada seragam di bagian...', '["A. Pundak/Epolet", "B. Lengan kanan", "C. Lengan kiri (di bawah tanda regu/barung)", "D. Dada kanan"]'::jsonb, 'C. Lengan kiri (di bawah tanda regu/barung)'),
(9, 'TKU Pramuka Siaga berbentuk janur (daun kelapa) yang melengkung. Janur satu tingkat menandakan tingkat...', '["A. Mula", "B. Bantu", "C. Tata", "D. Ramu"]'::jsonb, 'A. Mula'),
(9, 'TKU Pramuka Penggalang dipasang di lengan kiri seragam. Berbentuk mirip huruf V (manggar) berwarna dasar merah. Jika jumlah manggarnya dua, berarti tingkat...', '["A. Ramu", "B. Rakit", "C. Terap", "D. Garuda"]'::jsonb, 'B. Rakit'),
(9, 'TKU Pramuka Penegak dipasang pada seragam di bagian...', '["A. Lengan kanan", "B. Lengan kiri", "C. Dada kiri", "D. Pundak (Epolet)"]'::jsonb, 'D. Pundak (Epolet)'),
(9, 'Tanda Kecakapan Khusus (TKK) dipasang di...', '["A. Lengan kanan (mengelilingi badge daerah)", "B. Lengan kiri", "C. Dada kanan", "D. Topi/Baret"]'::jsonb, 'A. Lengan kanan (mengelilingi badge daerah)'),
(9, 'Maksimal jumlah TKK yang boleh dipasang di lengan kanan baju seragam Pramuka adalah...', '["A. 3 buah", "B. 5 buah", "C. 10 buah", "D. Sebanyak-banyaknya"]'::jsonb, 'B. 5 buah'),
(9, 'Jika seorang Pramuka memiliki lebih dari 5 buah TKK, maka kelebihan TKK tersebut harus dipasang di...', '["A. Lengan kiri", "B. Dada kanan", "C. Tetampan (Selendang TKK)", "D. Saku celana/rok"]'::jsonb, 'C. Tetampan (Selendang TKK)'),
(9, 'TKK berbentuk Lingkaran menandakan tingkat...', '["A. Purwa", "B. Madya", "C. Utama", "D. Garuda"]'::jsonb, 'A. Purwa'),
(9, 'TKK berbentuk Persegi (Bujur Sangkar) menandakan tingkat...', '["A. Purwa", "B. Madya", "C. Utama", "D. Khusus"]'::jsonb, 'B. Madya'),
(9, 'TKK berbentuk Segilima beraturan menandakan tingkat...', '["A. Purwa", "B. Madya", "C. Utama", "D. Master"]'::jsonb, 'C. Utama'),
(9, 'Warna dasar TKK bidang Agama, Mental, Spiritual, dan Pembentukan Watak adalah...', '["A. Kuning", "B. Merah", "C. Putih", "D. Hijau"]'::jsonb, 'A. Kuning'),
(9, 'Warna dasar TKK bidang Patriotisme dan Seni Budaya adalah...', '["A. Biru", "B. Merah", "C. Putih", "D. Hijau"]'::jsonb, 'B. Merah'),
(9, 'Warna dasar TKK bidang Kesehatan dan Ketangkasan adalah...', '["A. Putih", "B. Kuning", "C. Hijau", "D. Merah"]'::jsonb, 'A. Putih'),
(9, 'Warna dasar TKK bidang Keterampilan dan Teknik Pembangunan adalah...', '["A. Kuning", "B. Hijau", "C. Biru", "D. Putih"]'::jsonb, 'B. Hijau'),
(9, 'Warna dasar TKK bidang Sosial, Perikemanusiaan, Gotong Royong, Ketertiban Masyarakat, Perdamaian Dunia, dan Lingkungan Hidup adalah...', '["A. Biru", "B. Merah", "C. Hijau", "D. Kuning"]'::jsonb, 'A. Biru'),
(9, 'Tanda pengenal yang diberikan kepada seseorang sebagai penghargaan atas jasa, kesetiaan, dan darma baktinya disebut...', '["A. Tanda Jabatan", "B. Tanda Kecakapan", "C. Tanda Kehormatan", "D. Tanda Umum"]'::jsonb, 'C. Tanda Kehormatan'),
(9, 'Tanda Kehormatan berupa bintang yang diberikan kepada peserta didik atas kesetiaan dan keaktifannya selama satu tahun secara berturut-turut disebut...', '["A. Bintang Pancawarsa", "B. Bintang Tahunan", "C. Bintang Teladan", "D. Bintang Garuda"]'::jsonb, 'B. Bintang Tahunan'),
(9, 'Lencana Tanda Kehormatan "Pancawarsa" diberikan kepada anggota dewasa Gerakan Pramuka atas kesetiaannya setiap kelipatan masa bakti...', '["A. 1 tahun", "B. 3 tahun", "C. 5 tahun", "D. 10 tahun"]'::jsonb, 'C. 5 tahun'),
(9, 'Tanda Pramuka Garuda (Lencana Garuda) berbentuk...', '["A. Lingkaran dengan burung garuda di tengah", "B. Segi lima dengan relief burung garuda", "C. Bintang segi delapan", "D. Perisai dengan gambar tunas kelapa"]'::jsonb, 'B. Segi lima dengan relief burung garuda'),
(9, 'Tanda Kehormatan yang diberikan kepada anggota Gerakan Pramuka yang telah menunjukkan sikap laku yang utama dan bisa menjadi teladan bagi anggota lainnya disebut...', '["A. Lencana Darma Bakti", "B. Lencana Karya Bakti", "C. Lencana Teladan", "D. Lencana Melati"]'::jsonb, 'C. Lencana Teladan');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(12, 'Kata "Sandi" berasal dari bahasa Sanskerta, yang memiliki arti...', '["A. Tanda", "B. Rahasia", "C. Tulisan", "D. Isyarat"]'::jsonb, 'B. Rahasia'),
(12, 'Fungsi utama mempelajari sandi dalam kegiatan kepramukaan adalah untuk...', '["A. Menarik perhatian orang tua", "B. Melatih daya ingat, kecerdasan, dan ketelitian", "C. Menyembunyikan barang bawaan", "D. Syarat wajib berkemah"]'::jsonb, 'B. Melatih daya ingat, kecerdasan, dan ketelitian'),
(12, 'Penemu sistem telegraf dan kode Morse adalah seorang seniman dan penemu asal Amerika yang bernama...', '["A. Robert Baden-Powell", "B. Samuel F.B. Morse", "C. Alexander Graham Bell", "D. Thomas Alva Edison"]'::jsonb, 'B. Samuel F.B. Morse'),
(12, 'Kode Morse pertama kali ditemukan dan digunakan secara praktis pada tahun...', '["A. 1837", "B. 1850", "C. 1908", "D. 1912"]'::jsonb, 'A. 1837'),
(12, 'Dalam standar internasional, perbandingan durasi waktu antara bunyi/simbol "titik" dan "garis" pada sandi Morse adalah...', '["A. 1 : 2", "B. 1 : 3", "C. 2 : 3", "D. 1 : 4"]'::jsonb, 'B. 1 : 3'),
(12, 'Huruf yang direpresentasikan dengan satu titik (.) dalam sandi Morse adalah...', '["A. A", "B. E", "C. I", "D. T"]'::jsonb, 'B. E'),
(12, 'Huruf yang direpresentasikan dengan satu garis (-) dalam sandi Morse adalah...', '["A. M", "B. N", "C. T", "D. O"]'::jsonb, 'C. T'),
(12, 'Kode Morse untuk huruf "A" adalah...', '["A. .-", "B. -.", "C. ..", "D. --"]'::jsonb, 'A. .-'),
(12, 'Kode Morse untuk huruf "B" adalah...', '["A. -...", "B. -.-.", "C. -..", "D. -.-"]'::jsonb, 'A. -...'),
(12, 'Sinyal marabahaya darurat atau minta tolong standar internasional (SOS) dalam sandi Morse ditulis dengan...', '["A. --- ... ---", "B. ... --- ...", "C. ... ... ...", "D. --- --- ---"]'::jsonb, 'B. ... --- ...'),
(12, 'Kode Morse (...--) melambangkan angka...', '["A. 1", "B. 2", "C. 3", "D. 4"]'::jsonb, 'C. 3'),
(12, 'Kode Morse (---..) melambangkan angka...', '["A. 6", "B. 7", "C. 8", "D. 9"]'::jsonb, 'C. 8'),
(12, 'Kode Morse (----.) melambangkan angka...', '["A. 7", "B. 8", "C. 9", "D. 0"]'::jsonb, 'C. 9'),
(12, 'Tanda pemisah antar kata saat menulis sandi Morse di atas kertas biasanya menggunakan tanda...', '["A. Titik dua (:)", "B. Garis miring ganda (//)", "C. Tanda hubung (-)", "D. Garis bawah (_)"]'::jsonb, 'B. Garis miring ganda (//)'),
(12, 'Dalam pengiriman pesan Morse, tanda untuk memulai panggilan atau "Attention" biasanya menggunakan kode...', '["A. -.-.-.", "B. .-...-", "C. -.-.", "D. ...-.-"]'::jsonb, 'A. -.-.-.'),
(12, 'Isyarat "Pesan Selesai" (End of Message) dalam pengiriman Morse ditandai dengan kode gabungan huruf AR, yaitu...', '["A. .-.-.", "B. ...-.-", "C. -...-", "D. .-..."]'::jsonb, 'A. .-.-.'),
(12, 'Jika pengirim melakukan kesalahan saat mengirim sandi Morse, ia memberikan isyarat salah (E 8 kali) yang berbunyi...', '["A. --------", "B. ........", "C. .-.-.-.-", "D. -.-.-.-."]'::jsonb, 'B. ........'),
(12, 'Sandi yang menggunakan bentuk garis vertikal, horizontal, dan titik sebagai pengganti huruf disebut...', '["A. Sandi Rumput", "B. Sandi Kotak", "C. Sandi Angka", "D. Sandi Kimia"]'::jsonb, 'B. Sandi Kotak'),
(12, 'Sandi Kotak 1 terdiri dari dua macam bentuk pola kerangka, yaitu...', '["A. Garis lurus dan garis miring", "B. Palang tegak lurus dan silang (X)", "C. Lingkaran dan segitiga", "D. Persegi panjang dan jajar genjang"]'::jsonb, 'B. Palang tegak lurus dan silang (X)'),
(12, 'Dalam Sandi Kotak 1, masing-masing kotak pada kerangka palang maksimal diisi oleh...', '["A. 1 huruf", "B. 2 huruf", "C. 3 huruf", "D. 4 huruf"]'::jsonb, 'B. 2 huruf'),
(12, 'Dalam Sandi Kotak 1, huruf "B" digambarkan dengan bentuk sudut siku-siku terbuka ke atas-kanan, ditambah dengan...', '["A. Tanpa titik", "B. 1 titik", "C. 2 titik", "D. 3 titik"]'::jsonb, 'B. 1 titik'),
(12, 'Dalam Sandi Kotak 1, huruf "A" digambarkan dengan bentuk sudut siku-siku terbuka ke atas-kanan, ditambah dengan...', '["A. Tanpa titik", "B. 1 titik", "C. 2 titik", "D. Garis miring"]'::jsonb, 'A. Tanpa titik'),
(12, 'Perbedaan utama antara Sandi Kotak 1 dan Sandi Kotak 2 (versi Boyman) terletak pada...', '["A. Bentuk silangnya dihilangkan", "B. Setiap kotak berisi 3 huruf dan menggunakan maksimal 2 titik", "C. Huruf A sampai Z dibuat dalam satu baris", "D. Menggunakan angka sebagai pengganti titik"]'::jsonb, 'B. Setiap kotak berisi 3 huruf dan menggunakan maksimal 2 titik'),
(12, 'Dalam Sandi Kotak 2, huruf "C" ditandai dengan kotak yang sama dengan A dan B, namun menggunakan...', '["A. Tidak menggunakan titik", "B. Menggunakan 1 titik", "C. Menggunakan 2 titik", "D. Menggunakan 3 titik"]'::jsonb, 'C. Menggunakan 2 titik'),
(12, 'Sandi Kotak 3 memiliki bentuk dasar kerangka yang unik, yaitu susunan dari...', '["A. Segitiga dan lingkaran", "B. Belah ketupat (segi empat silang)", "C. Persegi panjang memanjang", "D. Garis-garis sejajar"]'::jsonb, 'B. Belah ketupat (segi empat silang)'),
(12, 'Sandi Rumput merupakan bentuk aplikasi visual lain dari...', '["A. Sandi Kotak", "B. Sandi Angka", "C. Sandi Morse", "D. Semaphore"]'::jsonb, 'C. Sandi Morse'),
(12, 'Pada Sandi Rumput, lambang titik (.) pada morse digambarkan dengan...', '["A. Rumput tinggi", "B. Rumput pendek", "C. Gundukan tanah", "D. Bunga"]'::jsonb, 'B. Rumput pendek'),
(12, 'Pada Sandi Rumput, lambang garis (-) pada morse digambarkan dengan...', '["A. Rumput tinggi", "B. Rumput pendek", "C. Pohon", "D. Batu"]'::jsonb, 'A. Rumput tinggi'),
(12, 'Sandi yang mengubah urutan abjad sedemikian rupa sehingga huruf "A" dibaca sebagai "N", "B" dibaca "O", dan seterusnya, disebut...', '["A. Sandi AZ", "B. Sandi AN", "C. Sandi Koordinat", "D. Sandi Geser"]'::jsonb, 'B. Sandi AN'),
(12, 'Kata "PRAMUKA" jika dipecahkan menggunakan Sandi AN akan berbunyi...', '["A. CENZHXN", "B. CENZHYA", "C. CENZHKN", "D. CRAMHXA"]'::jsonb, 'A. CENZHXN'),
(12, 'Sandi yang menukar huruf awal alfabet dengan huruf akhir (A=Z, B=Y, C=X) disebut...', '["A. Sandi AZ / Sandi Balik Abjad", "B. Sandi AN", "C. Sandi Cermin", "D. Sandi Rumput"]'::jsonb, 'A. Sandi AZ / Sandi Balik Abjad'),
(12, 'Dalam Sandi Angka dasar, di mana A=1, B=2, dst., maka susunan kode 16-18-1-13-21-11-1 dibaca...', '["A. PENGGALANG", "B. PANDU", "C. PRAMUKA", "D. PEMBINA"]'::jsonb, 'C. PRAMUKA'),
(12, 'Sandi Angka juga bisa divariasikan dengan awalan berbeda, misalnya A=0. Jika A=0, maka huruf C adalah angka...', '["A. 0", "B. 1", "C. 2", "D. 3"]'::jsonb, 'C. 2'),
(12, 'Sandi yang pengerjaannya menggunakan dua kata kunci yang digabungkan membentuk tabel baris dan kolom (koordinat), dan total huruf kuncinya berjumlah 10 tanpa pengulangan, disebut...', '["A. Sandi Angka", "B. Sandi Koordinat", "C. Sandi Jam", "D. Sandi Kimia"]'::jsonb, 'B. Sandi Koordinat'),
(12, 'Dua kata yang paling sering dijadikan kata kunci dalam Sandi Koordinat Pramuka adalah...', '["A. MERAH PUTIH", "B. PANDU DUNIA", "C. TUNAS KELAPA", "D. GARUDA JAYA"]'::jsonb, 'A. MERAH PUTIH'),
(12, 'Dalam Sandi Koordinat "MERAH PUTIH", huruf "M" mewakili...', '["A. Kolom pertama", "B. Baris pertama", "C. Angka nol", "D. Tanda spasi"]'::jsonb, 'B. Baris pertama'),
(12, 'Sandi yang memanfaatkan patokan interval waktu tertentu sebagai urutan abjad disebut...', '["A. Sandi Waktu", "B. Sandi Menit", "C. Sandi Jam", "D. Sandi Detik"]'::jsonb, 'C. Sandi Jam'),
(12, 'Pada Sandi Jam, jika ditentukan jam 08.00 adalah huruf A, dan interval beda waktu adalah 5 menit, maka huruf B ditulis dengan...', '["A. 08.01", "B. 08.05", "C. 08.10", "D. 08.15"]'::jsonb, 'B. 08.05'),
(12, 'Jika 07.00 = A dengan interval 5 menit, jam berapakah yang menunjukkan huruf C?', '["A. 07.05", "B. 07.10", "C. 07.15", "D. 07.20"]'::jsonb, 'B. 07.10'),
(12, 'Sandi yang mengadopsi cara penulisan unsur kimiawi, dan sebenarnya merupakan kamuflase dari sandi Morse, disebut...', '["A. Sandi Biologi", "B. Sandi Fisika", "C. Sandi Kimia", "D. Sandi Molekul"]'::jsonb, 'C. Sandi Kimia'),
(12, 'Dalam rumus Sandi Kimia Pramuka, huruf Vokal (A, I, U, E, O) berfungsi menggantikan posisi...', '["A. Tanda Titik (.) pada Morse", "B. Tanda Garis (-) pada Morse", "C. Tanda Spasi", "D. Huruf mati"]'::jsonb, 'A. Tanda Titik (.) pada Morse'),
(12, 'Dalam Sandi Kimia, huruf Konsonan (B, C, D, F, dst) berfungsi menggantikan posisi...', '["A. Tanda Titik (.) pada Morse", "B. Tanda Garis (-) pada Morse", "C. Tanda Spasi", "D. Angka"]'::jsonb, 'B. Tanda Garis (-) pada Morse'),
(12, 'Kode Morse ".-" (Huruf A) jika diubah ke dalam Sandi Kimia bisa ditulis menjadi kombinasi Vokal-Konsonan seperti...', '["A. OH", "B. O2", "C. H2O", "D. CO2"]'::jsonb, 'A. OH'),
(12, 'Kata yang disembunyikan dengan menyisipkan kata "AND" di antara setiap hurufnya disebut Sandi AND. Jika tertulis "PAND R AND A M AND U K AND A", kata aslinya adalah...', '["A. PANDU", "B. PRAJA", "C. PRAMUKA", "D. PENGGALANG"]'::jsonb, 'C. PRAMUKA'),
(12, 'Sandi yang bentuknya menyerupai lekukan garis-garis bergelombang, di mana lekukan kecil adalah titik dan lekukan besar adalah garis, dinamakan...', '["A. Sandi Sungai", "B. Sandi Akar", "C. Sandi Arab", "D. Sandi Ular / Sandi Gergaji"]'::jsonb, 'D. Sandi Ular / Sandi Gergaji'),
(12, 'Sandi yang cara membacanya sama dengan cara membaca tulisan Arab, yaitu dari kanan ke kiri, disebut...', '["A. Sandi Balik Kata", "B. Sandi Cermin", "C. Sandi Arab", "D. Sandi Mesir"]'::jsonb, 'C. Sandi Arab'),
(12, 'Kata "AKUMARP" jika dipecahkan menggunakan kaidah Sandi Arab atau Sandi Balik akan berbunyi...', '["A. PRAMUKA", "B. GARUDA", "C. PANDU", "D. SIAGA"]'::jsonb, 'A. PRAMUKA'),
(12, 'Selain menggunakan peluit dan kertas, sandi Morse di malam hari sangat efektif dikirimkan menggunakan media...', '["A. Bendera", "B. Senter / Cahaya", "C. Asap", "D. Ketukan batu"]'::jsonb, 'B. Senter / Cahaya'),
(12, 'Pengiriman isyarat komunikasi tradisional menggunakan kepulan asap sering dikaitkan dengan suku Indian, namun dalam Pramuka juga diajarkan sebagai bagian dari...', '["A. Sandi Asap", "B. Sandi Udara", "C. Sandi Api", "D. Sandi Darurat"]'::jsonb, 'A. Sandi Asap'),
(12, 'Sandi yang menggunakan titik-titik timbul untuk membantu penyandang tunanetra membaca, dan sering masuk dalam materi wawasan komunikasi pandu, diciptakan oleh...', '["A. Louis Braille", "B. Samuel Morse", "C. Lord Baden-Powell", "D. Claude Chappe"]'::jsonb, 'A. Louis Braille');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(15, 'Dalam kepramukaan, benda yang digunakan untuk membuat simpul dan ikatan disebut...', '["A. Simpul", "B. Tali", "C. Ikatan", "D. Jerat"]'::jsonb, 'B. Tali'),
(15, 'Pertemuan antara tali dengan tali (membentuk suatu bentuk tertentu) disebut...', '["A. Tali", "B. Simpul", "C. Ikatan", "D. Pionering"]'::jsonb, 'B. Simpul'),
(15, 'Pertemuan antara tali dengan benda lain, seperti tongkat atau kayu, disebut...', '["A. Tali", "B. Simpul", "C. Ikatan", "D. Anyaman"]'::jsonb, 'C. Ikatan'),
(15, 'Simpul yang berguna untuk menjaga agar ujung tali tidak terurai atau lepas serat-seratnya adalah...', '["A. Simpul Ujung Tali (Whipping)", "B. Simpul Anyam", "C. Simpul Delapan", "D. Simpul Erat"]'::jsonb, 'A. Simpul Ujung Tali (Whipping)'),
(15, 'Simpul yang digunakan untuk menyambung dua utas tali yang sama besar dan dalam keadaan tidak licin (kering) adalah...', '["A. Simpul Hidup", "B. Simpul Mati (Reef Knot)", "C. Simpul Anyam", "D. Simpul Kembar"]'::jsonb, 'B. Simpul Mati (Reef Knot)'),
(15, 'Ciri khas dari Simpul Mati (Reef Knot) adalah...', '["A. Sulit untuk dilepaskan kembali", "B. Mudah dilepaskan meskipun ditarik kencang", "C. Hanya bisa digunakan pada tali basah", "D. Membutuhkan tongkat untuk membuatnya"]'::jsonb, 'B. Mudah dilepaskan meskipun ditarik kencang'),
(15, 'Simpul yang digunakan untuk menyambung dua utas tali yang tidak sama besar dan dalam keadaan kering adalah...', '["A. Simpul Anyam (Sheet Bend)", "B. Simpul Anyam Berganda", "C. Simpul Kembar", "D. Simpul Mati"]'::jsonb, 'A. Simpul Anyam (Sheet Bend)'),
(15, 'Jika dua utas tali yang akan disambung ukurannya tidak sama besar dan dalam keadaan basah/licin, simpul yang paling tepat digunakan adalah...', '["A. Simpul Anyam (Sheet Bend)", "B. Simpul Anyam Berganda (Double Sheet Bend)", "C. Simpul Mati", "D. Simpul Hidup"]'::jsonb, 'B. Simpul Anyam Berganda (Double Sheet Bend)'),
(15, 'Simpul yang digunakan untuk menyambung dua utas tali yang sama besar dan dalam keadaan licin/basah (sering digunakan pemancing) adalah...', '["A. Simpul Nelayan / Kembar (Fisherman''s Knot)", "B. Simpul Pangkal", "C. Simpul Tarik", "D. Simpul Jangkar"]'::jsonb, 'A. Simpul Nelayan / Kembar (Fisherman''s Knot)'),
(15, 'Fungsi utama dari Simpul Tiang (Bowline) adalah...', '["A. Mengikat tiang tenda agar kuat", "B. Mengikat leher binatang agar tidak tercekik", "C. Menyambung tali yang putus", "D. Memendekkan tali yang terlalu panjang"]'::jsonb, 'B. Mengikat leher binatang agar tidak tercekik'),
(15, 'Simpul yang berfungsi untuk menurunkan orang dari atas gedung atau jurang, yang terdiri dari dua sosok yang menahan dada dan paha, disebut...', '["A. Simpul Kursi (Fireman''s Chair Knot)", "B. Simpul Penyelamat", "C. Simpul Tiang Berganda", "D. Simpul Tarik"]'::jsonb, 'A. Simpul Kursi (Fireman''s Chair Knot)'),
(15, 'Simpul dasar yang selalu digunakan untuk memulai dan mengakhiri suatu ikatan pionering (seperti ikatan palang atau silang) adalah...', '["A. Simpul Jangkar", "B. Simpul Pangkal (Clove Hitch)", "C. Simpul Tambat", "D. Simpul Mati"]'::jsonb, 'B. Simpul Pangkal (Clove Hitch)'),
(15, 'Simpul yang berfungsi untuk menautkan tali pada benda/kayu dengan cepat, dan sering digunakan untuk membuat tandu darurat, adalah...', '["A. Simpul Jangkar (Cow Hitch)", "B. Simpul Kembar", "C. Simpul Anyam", "D. Simpul Delapan"]'::jsonb, 'A. Simpul Jangkar (Cow Hitch)'),
(15, 'Simpul Tambat (Timber Hitch) memiliki fungsi utama untuk...', '["A. Menarik benda yang berat, seperti balok kayu", "B. Mengikat leher hewan", "C. Menyambung tali berukuran sama", "D. Mengakhiri ikatan palang"]'::jsonb, 'A. Menarik benda yang berat, seperti balok kayu'),
(15, 'Simpul yang digunakan untuk turun ke jurang atau pohon, dengan kelebihan tali dapat dilepas dan ditarik kembali dari bawah, disebut...', '["A. Simpul Delapan", "B. Simpul Tarik (Highwayman''s Hitch)", "C. Simpul Hidup", "D. Simpul Tiang"]'::jsonb, 'B. Simpul Tarik (Highwayman''s Hitch)'),
(15, 'Simpul yang sangat sering digunakan oleh pemanjat tebing sebagai pengaman di ujung tali (stopper) karena tidak mudah merosot adalah...', '["A. Simpul Mati", "B. Simpul Delapan (Figure of Eight)", "C. Simpul Pangkal", "D. Simpul Kembar"]'::jsonb, 'B. Simpul Delapan (Figure of Eight)'),
(15, 'Ikatan yang digunakan untuk menyambung dua buah tongkat yang bersilangan dengan sudut 90 derajat (tegak lurus) disebut...', '["A. Ikatan Silang (Diagonal Lashing)", "B. Ikatan Palang (Square Lashing)", "C. Ikatan Canggah", "D. Ikatan Kaki Tiga"]'::jsonb, 'B. Ikatan Palang (Square Lashing)'),
(15, 'Ikatan Palang (Square Lashing) selalu diawali dengan simpul pangkal pada...', '["A. Tongkat yang posisinya melintang di atas", "B. Tongkat yang posisinya tegak lurus (berdiri)", "C. Pertemuan kedua tongkat", "D. Ujung tali saja"]'::jsonb, 'B. Tongkat yang posisinya tegak lurus (berdiri)'),
(15, 'Ikatan yang digunakan untuk menautkan dua buah tongkat yang bersilangan, tetapi sudutnya tidak membentuk 90 derajat (kurang/lebih dari 90 derajat), disebut...', '["A. Ikatan Silang (Diagonal Lashing)", "B. Ikatan Palang", "C. Ikatan Canggah", "D. Ikatan Kaki Tiga"]'::jsonb, 'A. Ikatan Silang (Diagonal Lashing)'),
(15, 'Ikatan Silang (Diagonal Lashing) pada awal pembuatannya dimulai dengan simpul...', '["A. Simpul Pangkal", "B. Simpul Tambat / Simpul Silang (Timber Hitch)", "C. Simpul Jangkar", "D. Simpul Mati"]'::jsonb, 'B. Simpul Tambat / Simpul Silang (Timber Hitch)'),
(15, 'Dalam membuat ikatan pionering (Palang/Silang), setelah tali dililitkan mengelilingi tongkat, langkah selanjutnya adalah membuat lilitan pengunci di celah antara dua tongkat yang disebut...', '["A. Whipping", "B. Splicing", "C. Frapping", "D. Bight"]'::jsonb, 'C. Frapping'),
(15, 'Tujuan utama melakukan Frapping pada ikatan pionering adalah untuk...', '["A. Mempercantik tampilan ikatan", "B. Menghabiskan sisa tali", "C. Mengencangkan seluruh lilitan agar ikatan menjadi kaku dan kuat", "D. Memudahkan tali untuk dilepas kembali"]'::jsonb, 'C. Mengencangkan seluruh lilitan agar ikatan menjadi kaku dan kuat'),
(15, 'Ikatan yang digunakan untuk menyambung dua buah tongkat secara lurus (memperpanjang tongkat) disebut...', '["A. Ikatan Palang", "B. Ikatan Canggah / Sambung Tongkat (Shear Lashing)", "C. Ikatan Silang", "D. Ikatan Kaki Tiga"]'::jsonb, 'B. Ikatan Canggah / Sambung Tongkat (Shear Lashing)'),
(15, 'Untuk membuat tiang bendera darurat yang bisa berdiri sendiri (tanpa ditanam), digunakan 3 tongkat penyangga utama yang diikat menggunakan...', '["A. Ikatan Canggah", "B. Ikatan Palang", "C. Ikatan Kaki Tiga (Tripod Lashing)", "D. Ikatan Silang"]'::jsonb, 'C. Ikatan Kaki Tiga (Tripod Lashing)'),
(15, 'Tali pramuka standar di Indonesia (yang sering diikatkan di pinggang seragam) umumnya terbuat dari bahan...', '["A. Katun (Cotton)", "B. Nilon (Nylon)", "C. Baja", "D. Ijuk"]'::jsonb, 'A. Katun (Cotton)'),
(15, 'Panjang standar tali pramuka perseorangan yang digunakan di Indonesia biasanya berkisar antara...', '["A. 2 hingga 3 meter", "B. 5 hingga 10 meter", "C. 15 hingga 20 meter", "D. 30 meter"]'::jsonb, 'B. 5 hingga 10 meter'),
(15, 'Serat tali yang berasal dari bahan alam (tumbuhan), contohnya adalah...', '["A. Nilon dan Poliester", "B. Manila, Sisal, dan Katun", "C. Dacron dan Polypropylene", "D. Kernmantle"]'::jsonb, 'B. Manila, Sisal, dan Katun'),
(15, 'Salah satu kelemahan utama tali yang terbuat dari bahan alam (seperti rami/manila) dibandingkan bahan sintetis adalah...', '["A. Terlalu licin saat diikat", "B. Mudah lapuk, membusuk, dan menyerap air", "C. Harganya sangat mahal", "D. Tidak bisa dibuat simpul mati"]'::jsonb, 'B. Mudah lapuk, membusuk, dan menyerap air'),
(15, 'Tali Kernmantle merupakan tali berteknologi tinggi yang biasa digunakan dalam olahraga alam bebas. Tali ini terdiri dari dua bagian utama, yaitu...', '["A. Inti (Core) dan Mantel (Sheath)", "B. Kapas dan Nilon", "C. Serat dan Karet", "D. Pilinan dan Anyaman"]'::jsonb, 'A. Inti (Core) dan Mantel (Sheath)'),
(15, 'Tali Kernmantle yang memiliki daya lentur (stretch) tinggi, berguna untuk meredam hentakan saat pemanjat terjatuh, disebut...', '["A. Kernmantle Static", "B. Kernmantle Dynamic", "C. Kernmantle Semi-static", "D. Webbing"]'::jsonb, 'B. Kernmantle Dynamic'),
(15, 'Tali Kernmantle yang kaku dan daya lenturnya sangat rendah, cocok digunakan untuk turun tebing (rappelling) atau susur gua (caving), disebut...', '["A. Kernmantle Static", "B. Kernmantle Dynamic", "C. Webbing", "D. Prusik"]'::jsonb, 'A. Kernmantle Static'),
(15, 'Tali pipih berserat sintetis yang sangat kuat, sering digunakan sebagai sabuk (harness) atau anchor dalam panjat tebing, disebut...', '["A. Manila", "B. Webbing", "C. Sisal", "D. Carmantle"]'::jsonb, 'B. Webbing'),
(15, 'Simpul yang khusus digunakan untuk menyambung tali webbing dinamakan...', '["A. Simpul Anyam", "B. Simpul Pita (Water Knot / Tape Knot)", "C. Simpul Delapan", "D. Simpul Kembar"]'::jsonb, 'B. Simpul Pita (Water Knot / Tape Knot)'),
(15, 'Teknik memendekkan tali tanpa harus memotongnya dapat dilakukan menggunakan...', '["A. Simpul Mati", "B. Anyaman Rantai (Chain Sinnet)", "C. Simpul Ujung Tali", "D. Ikatan Palang"]'::jsonb, 'B. Anyaman Rantai (Chain Sinnet)'),
(15, 'Simpul yang sering digunakan untuk menjerat atau menangkap binatang buas (jerat bergeser) adalah...', '["A. Simpul Hidup (Slip Knot / Noose)", "B. Simpul Mati", "C. Simpul Pangkal", "D. Simpul Anyam"]'::jsonb, 'A. Simpul Hidup (Slip Knot / Noose)'),
(15, 'Seni kerajinan merangkai dan membuat simpul tali menjadi barang-barang yang berguna atau hiasan disebut...', '["A. Pionering", "B. Macrame", "C. Splicing", "D. Frapping"]'::jsonb, 'B. Macrame'),
(15, 'Istilah "Splicing" dalam ilmu per-tali-an berarti...', '["A. Memotong tali", "B. Mewarnai tali", "C. Menganyam tali (menyambung tanpa simpul, dengan menyatukan serat-seratnya)", "D. Menggulung tali"]'::jsonb, 'C. Menganyam tali (menyambung tanpa simpul, dengan menyatukan serat-seratnya)'),
(15, 'Cara perawatan tali yang benar setelah digunakan dalam keadaan basah/kotor adalah...', '["A. Langsung digulung dan dimasukkan ke dalam plastik tertutup", "B. Dijemur di bawah terik matahari langsung", "C. Dicuci bersih lalu diangin-anginkan di tempat teduh (tidak terkena matahari langsung)", "D. Disetrika agar lurus kembali"]'::jsonb, 'C. Dicuci bersih lalu diangin-anginkan di tempat teduh (tidak terkena matahari langsung)'),
(15, 'Bangunan darurat hasil karya pramuka (seperti menara intai, jembatan, gapura) yang dibuat dari gabungan tongkat dan tali disebut...', '["A. Bivak", "B. Pionering (Pioneering)", "C. Maket", "D. Boven"]'::jsonb, 'B. Pionering (Pioneering)'),
(15, 'Miniatur dari bangunan pionering, yang biasanya dibuat sebagai konsep dasar menggunakan lidi atau tusuk sate dan benang, disebut...', '["A. Sketsa", "B. Maket Pionering", "C. Diorama", "D. Purwarupa"]'::jsonb, 'B. Maket Pionering'),
(15, 'Dalam pembuatan Tandu Darurat (Drag Stretcher), kebutuhan material standarnya adalah...', '["A. 4 tongkat panjang, 4 tali", "B. 2 tongkat panjang (2 meter), 2 tongkat pendek (60 cm), dan tali pramuka secukupnya", "C. 1 tongkat panjang, 2 tongkat pendek", "D. Hanya tali saja"]'::jsonb, 'B. 2 tongkat panjang (2 meter), 2 tongkat pendek (60 cm), dan tali pramuka secukupnya'),
(15, 'Simpul yang digunakan untuk memegang erat tubuh tongkat saat membuat anyaman (jaring) pada tandu darurat adalah...', '["A. Simpul Pangkal dan Simpul Jangkar", "B. Simpul Mati", "C. Simpul Anyam", "D. Simpul Delapan"]'::jsonb, 'A. Simpul Pangkal dan Simpul Jangkar'),
(15, 'Setiap kali membuat simpul pada seutas tali, kekuatan asli (Breaking Strength) tali tersebut akan...', '["A. Bertambah kuat", "B. Menurun/Berkurang (Knot Efficiency)", "C. Tetap tidak berubah", "D. Menjadi elastis"]'::jsonb, 'B. Menurun/Berkurang (Knot Efficiency)'),
(15, 'Dalam anatomi tali (Rope Anatomy), ujung tali yang digunakan secara aktif untuk membuat simpul atau ikatan disebut...', '["A. Standing Part", "B. Working End", "C. Bight", "D. Loop"]'::jsonb, 'B. Working End'),
(15, 'Bagian tali yang pasif, panjang, dan tidak digunakan untuk membentuk simpul disebut...', '["A. Standing Part", "B. Working End", "C. Loop", "D. Tail"]'::jsonb, 'A. Standing Part'),
(15, 'Bentuk lengkungan tali atau tali yang ditekuk menyerupai huruf U disebut...', '["A. Loop", "B. Bight", "C. Turn", "D. Hitch"]'::jsonb, 'B. Bight'),
(15, 'Bentuk tali yang menyilang pada dirinya sendiri hingga membentuk sebuah lingkaran (cincin) disebut...', '["A. Bight", "B. Loop", "C. Hitch", "D. Splice"]'::jsonb, 'B. Loop'),
(15, 'Lilitan tali yang mengelilingi suatu benda sebanyak satu putaran penuh (360 derajat) disebut...', '["A. Turn", "B. Bight", "C. Loop", "D. End"]'::jsonb, 'A. Turn'),
(15, 'Simpul yang dibuat di tengah-tengah tali tanpa menggunakan ujung tali, menghasilkan sosok (loop) paten yang sangat kuat dan bisa ditarik dari tiga arah, dinamakan...', '["A. Simpul Kupu-kupu (Alpine Butterfly Knot)", "B. Simpul Mati", "C. Simpul Anyam", "D. Simpul Tarik"]'::jsonb, 'A. Simpul Kupu-kupu (Alpine Butterfly Knot)'),
(15, 'Simpul gesekan (Friction Hitch) yang dibuat menggunakan tali kecil (prusik cord) yang dililitkan pada tali utama yang lebih besar, biasa digunakan untuk memanjat tali (ascending), adalah...', '["A. Simpul Pangkal", "B. Simpul Prusik", "C. Simpul Tiang", "D. Simpul Jangkar"]'::jsonb, 'B. Simpul Prusik');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(20, 'Alat navigasi penunjuk arah angin yang bekerja berdasarkan gaya medan magnet bumi adalah...', '["A. Altimeter", "B. Kompas", "C. Barometer", "D. Sextant"]'::jsonb, 'B. Kompas'),
(20, 'Arah utara yang ditunjukkan oleh jarum kompas disebut...', '["A. Utara Sebenarnya (True North)", "B. Utara Magnetis (Magnetic North)", "C. Utara Peta (Grid North)", "D. Utara Kutub"]'::jsonb, 'B. Utara Magnetis (Magnetic North)'),
(20, 'Jenis kompas yang paling sering digunakan oleh Pramuka untuk membidik sasaran secara akurat karena dilengkapi prisma pembesar adalah...', '["A. Kompas Bidik (Prisma)", "B. Kompas Silva (Orientering)", "C. Kompas Geologi", "D. Kompas Bintang"]'::jsonb, 'A. Kompas Bidik (Prisma)'),
(20, 'Jenis kompas yang badannya tembus pandang dan sangat ideal digunakan di atas peta (biasa digunakan untuk olahraga Orienteering) adalah...', '["A. Kompas Bidik", "B. Kompas Silva", "C. Kompas Lensa", "D. Kompas Digital"]'::jsonb, 'B. Kompas Silva'),
(20, 'Bagian kompas bidik yang berupa benang/kawat halus untuk membidik sasaran agar tepat pada target disebut...', '["A. Visir", "B. Dial", "C. Kaca Pembesar", "D. Jarum Penunjuk"]'::jsonb, 'A. Visir'),
(20, 'Permukaan kompas di mana tertera angka derajat dan huruf mata angin disebut...', '["A. Visir", "B. Dial", "C. Kaca Pembesar", "D. Cincin Jempol"]'::jsonb, 'B. Dial'),
(20, 'Angka derajat untuk arah Timur (East) pada dial kompas adalah...', '["A. 0 derajat", "B. 90 derajat", "C. 180 derajat", "D. 270 derajat"]'::jsonb, 'B. 90 derajat'),
(20, 'Angka derajat untuk arah Selatan (South) pada dial kompas adalah...', '["A. 90 derajat", "B. 180 derajat", "C. 270 derajat", "D. 360 derajat"]'::jsonb, 'B. 180 derajat'),
(20, 'Arah Barat Daya terletak di antara Selatan dan Barat, dengan angka derajat...', '["A. 135 derajat", "B. 225 derajat", "C. 315 derajat", "D. 45 derajat"]'::jsonb, 'B. 225 derajat'),
(20, 'Tenggara adalah arah mata angin yang berada pada derajat...', '["A. 45 derajat", "B. 135 derajat", "C. 225 derajat", "D. 315 derajat"]'::jsonb, 'B. 135 derajat'),
(20, 'Cara memegang kompas bidik yang benar agar akurat adalah...', '["A. Diletakkan mendatar sejajar dada/mata dan tenang", "B. Dimiringkan 45 derajat", "C. Didekatkan tepat di depan hidung", "D. Dipegang lurus ke atas kepala"]'::jsonb, 'A. Diletakkan mendatar sejajar dada/mata dan tenang'),
(20, 'Sudut yang dibentuk antara arah Utara Magnetis dengan arah sasaran (target) yang kita bidik disebut...', '["A. Back Azimuth", "B. Azimuth", "C. Deklinasi", "D. Inclinasi"]'::jsonb, 'B. Azimuth'),
(20, 'Sasaran balik atau sudut balikan dari target ke titik kita berdiri disebut...', '["A. Deklinasi", "B. Azimuth", "C. Back Azimuth (Sasaran Balik)", "D. Resection"]'::jsonb, 'C. Back Azimuth (Sasaran Balik)'),
(20, 'Rumus untuk mencari Back Azimuth jika Azimuth bidikan LEBIH DARI 180 derajat adalah...', '["A. Azimuth + 180", "B. Azimuth - 180", "C. Azimuth + 90", "D. Azimuth - 90"]'::jsonb, 'B. Azimuth - 180'),
(20, 'Rumus untuk mencari Back Azimuth jika Azimuth bidikan KURANG DARI 180 derajat adalah...', '["A. Azimuth - 180", "B. Azimuth + 180", "C. Azimuth x 2", "D. Azimuth / 2"]'::jsonb, 'B. Azimuth + 180'),
(20, 'Jika kita membidik sebuah pohon dan didapat Azimuth 60 derajat, maka Back Azimuth-nya adalah...', '["A. 120 derajat", "B. 180 derajat", "C. 240 derajat", "D. 300 derajat"]'::jsonb, 'C. 240 derajat'),
(20, 'Jika target yang dibidik berada di arah 250 derajat, maka Back Azimuth-nya adalah...', '["A. 70 derajat", "B. 100 derajat", "C. 300 derajat", "D. 430 derajat"]'::jsonb, 'A. 70 derajat'),
(20, 'Teknik menentukan posisi kita yang belum diketahui di atas peta dengan cara membidik dua titik kenampakan alam yang sudah diketahui di peta disebut...', '["A. Intersection", "B. Resection", "C. Orientasi Peta", "D. Azimuth"]'::jsonb, 'B. Resection'),
(20, 'Teknik menentukan posisi suatu titik/benda lain yang belum diketahui di peta, dengan cara membidiknya dari dua titik stasiun yang berbeda, disebut...', '["A. Intersection", "B. Resection", "C. Eksplorasi", "D. Pemetaan"]'::jsonb, 'A. Intersection'),
(20, 'Penyimpangan sudut antara Utara Sebenarnya (True North) dan Utara Magnetik bumi disebut...', '["A. Deklinasi", "B. Inclinasi", "C. Deviasi", "D. Variasi"]'::jsonb, 'A. Deklinasi'),
(20, 'Penyimpangan jarum kompas karena adanya pengaruh logam atau magnet di sekitarnya disebut...', '["A. Deklinasi", "B. Resection", "C. Deviasi", "D. Inclinasi"]'::jsonb, 'C. Deviasi'),
(20, 'Gambar permukaan bumi yang diproyeksikan pada bidang datar dengan skala tertentu disebut...', '["A. Sketsa", "B. Maket", "C. Peta", "D. Denah"]'::jsonb, 'C. Peta'),
(20, 'Peta yang menggambarkan tinggi rendahnya permukaan bumi (relief) secara detail menggunakan garis-garis ketinggian disebut...', '["A. Peta Tematik", "B. Peta Topografi", "C. Peta Pita", "D. Peta Perjalanan"]'::jsonb, 'B. Peta Topografi'),
(20, 'Garis khayal pada peta topografi yang menghubungkan titik-titik dengan ketinggian yang sama disebut...', '["A. Garis Khatulistiwa", "B. Garis Bujur", "C. Garis Kontur", "D. Garis Lintang"]'::jsonb, 'C. Garis Kontur'),
(20, 'Ciri khas dari garis kontur adalah jika garis-garis tersebut jaraknya tergambar sangat rapat, itu menandakan daerah tersebut adalah...', '["A. Lereng yang landai", "B. Lembah yang datar", "C. Lereng yang terjal/curam", "D. Danau"]'::jsonb, 'C. Lereng yang terjal/curam'),
(20, 'Garis kontur yang bergerigi atau memiliki garis-garis kecil yang mengarah ke dalam biasanya menandakan...', '["A. Puncak gunung", "B. Kawah atau depresi (cekungan)", "C. Sungai", "D. Jalan raya"]'::jsonb, 'B. Kawah atau depresi (cekungan)'),
(20, 'Peta berskala 1 : 25.000 berarti 1 cm di peta mewakili jarak sebenarnya di lapangan sejauh...', '["A. 25 meter", "B. 250 meter", "C. 2.500 meter", "D. 25.000 meter (25 km)"]'::jsonb, 'B. 250 meter'),
(20, 'Jika jarak antara desa A dan B di peta dengan skala 1:50.000 adalah 4 cm, maka jarak sebenarnya adalah...', '["A. 2 km", "B. 4 km", "C. 20 km", "D. 200 km"]'::jsonb, 'A. 2 km'),
(20, 'Warna Hijau pada peta topografi standar biasanya melambangkan...', '["A. Perairan", "B. Pemukiman", "C. Vegetasi/Hutan", "D. Jalan raya"]'::jsonb, 'C. Vegetasi/Hutan'),
(20, 'Warna Biru pada peta topografi standar melambangkan...', '["A. Dataran tinggi", "B. Bentang air (sungai, danau, laut)", "C. Hutan", "D. Pemukiman"]'::jsonb, 'B. Bentang air (sungai, danau, laut)'),
(20, 'Peta khusus yang digambar oleh Pramuka saat melakukan perjalanan atau penjelajahan, digambar dari bawah ke atas pada kertas yang digulung, disebut...', '["A. Peta Topografi", "B. Peta Tematik", "C. Peta Pita", "D. Peta Bintang"]'::jsonb, 'C. Peta Pita'),
(20, 'Arah pembuatan dan penulisan Peta Pita selalu dimulai dari...', '["A. Kanan ke kiri", "B. Atas ke bawah", "C. Kiri ke kanan", "D. Bawah ke atas"]'::jsonb, 'D. Bawah ke atas'),
(20, 'Fungsi utama pembuatan Peta Pita adalah...', '["A. Sebagai alat ukur tinggi pohon", "B. Menggambarkan situasi dan kondisi rute perjalanan yang dilalui secara detail", "C. Untuk mencari letak gunung", "D. Menghitung luas wilayah"]'::jsonb, 'B. Menggambarkan situasi dan kondisi rute perjalanan yang dilalui secara detail'),
(20, 'Kolom yang biasanya TIDAK ADA dalam format standar Peta Pita adalah...', '["A. Kolom Waktu", "B. Kolom Cuaca", "C. Kolom Harga Tiket", "D. Kolom Arah (Azimuth)"]'::jsonb, 'C. Kolom Harga Tiket'),
(20, 'Untuk mengukur jarak saat membuat peta pita tanpa alat ukur meteran, Pramuka sering menggunakan metode...', '["A. Menghitung jumlah langkah kaki ganda/tunggal", "B. Menghitung durasi jam tangan", "C. Menerka dengan mata", "D. Menggunakan kecepatan angin"]'::jsonb, 'A. Menghitung jumlah langkah kaki ganda/tunggal'),
(20, 'Dalam Peta Pita, kolom "Keterangan/Kenampakan Alam" digunakan untuk menggambar...', '["A. Kompas", "B. Sketsa bangunan, pohon, jembatan, dan tanda medan yang dilihat di kiri-kanan jalan", "C. Wajah anggota regu", "D. Rencana menu makanan"]'::jsonb, 'B. Sketsa bangunan, pohon, jembatan, dan tanda medan yang dilihat di kiri-kanan jalan'),
(20, 'Jika kita tersesat di hutan pada siang hari tanpa kompas, arah matahari terbenam dapat digunakan sebagai patokan dasar arah...', '["A. Timur", "B. Barat", "C. Utara", "D. Selatan"]'::jsonb, 'B. Barat'),
(20, 'Tanda alam dari pohon yang bisa dijadikan panduan arah di hutan adalah...', '["A. Daun yang lebih hijau menunjuk ke Utara", "B. Lumut yang lebih tebal pada batang pohon biasanya mengarah ke matahari terbit (Timur) atau terbenam (Barat)", "C. Lumut yang lebih tebal di batang pohon biasanya berada di sisi yang jarang terkena matahari (menghadap Barat/Timur tergantung musim, tapi paling aman sisi berlumut lebat sering dihindari angin siang/menghadap lembab)", "D. Ranting yang lebih lebat dan panjang biasanya tumbuh ke arah yang banyak mendapat sinar matahari"]'::jsonb, 'D. Ranting yang lebih lebat dan panjang biasanya tumbuh ke arah yang banyak mendapat sinar matahari'),
(20, 'Bintang yang sering digunakan sebagai penunjuk arah Utara pada malam hari di belahan bumi utara/ekuator adalah...', '["A. Bintang Pari (Crux)", "B. Bintang Biduk (Ursa Major) / Polaris", "C. Bintang Kejora", "D. Sabuk Orion"]'::jsonb, 'B. Bintang Biduk (Ursa Major) / Polaris'),
(20, 'Rasi bintang yang bentuknya seperti layang-layang atau salib dan sering digunakan untuk mencari arah Selatan adalah...', '["A. Rasi Bintang Pari (Gubuk Penceng / Crux)", "B. Ursa Minor", "C. Cassiopeia", "D. Pegasus"]'::jsonb, 'A. Rasi Bintang Pari (Gubuk Penceng / Crux)'),
(20, 'Menyamakan posisi Utara pada peta dengan Utara sebenarnya di lapangan sebelum menggunakan peta disebut...', '["A. Navigasi", "B. Orientasi Peta", "C. Resection", "D. Azimuth"]'::jsonb, 'B. Orientasi Peta'),
(20, 'Alat bantu navigasi modern yang menggunakan konstelasi satelit untuk menentukan koordinat dan posisi di bumi adalah...', '["A. Radar", "B. Sonar", "C. GPS (Global Positioning System)", "D. Telegraf"]'::jsonb, 'C. GPS (Global Positioning System)'),
(20, 'Garis lintang 0 derajat yang membelah bumi menjadi bagian utara dan selatan disebut...', '["A. Garis Meridian Utama (Greenwich)", "B. Garis Khatulistiwa (Equator)", "C. Garis Balik Utara", "D. Garis Bujur"]'::jsonb, 'B. Garis Khatulistiwa (Equator)'),
(20, 'Garis bujur 0 derajat yang menjadi patokan waktu dunia terletak di kota...', '["A. London (Greenwich)", "B. Paris", "C. Washington DC", "D. Tokyo"]'::jsonb, 'A. London (Greenwich)'),
(20, 'Format koordinat Geografis yang umum digunakan dalam peta adalah...', '["A. Kilometer dan Meter", "B. Derajat, Menit, Detik (DMS)", "C. Mil dan Yard", "D. Sentimeter"]'::jsonb, 'B. Derajat, Menit, Detik (DMS)'),
(20, 'Saat membaca koordinat pada peta topografi dengan sistem UTM/Grid (Kotak), aturan dasar membacanya adalah...', '["A. Baca sumbu vertikal (Y) dulu, lalu horizontal (X)", "B. Baca ke arah Timur dulu (sumbu X), baru ke Utara (sumbu Y) / Easting lalu Northing", "C. Bebas dari mana saja", "D. Baca garis miring"]'::jsonb, 'B. Baca ke arah Timur dulu (sumbu X), baru ke Utara (sumbu Y) / Easting lalu Northing'),
(20, 'Titik ketinggian absolut suatu tempat yang tercetak di peta topografi (biasanya berupa segitiga atau titik dengan angka) disebut...', '["A. Spot Height (Titik Triangulasi)", "B. Kontur Indeks", "C. Interval", "D. Azimuth"]'::jsonb, 'A. Spot Height (Titik Triangulasi)'),
(20, 'Beda tinggi atau jarak vertikal antara satu garis kontur dengan garis kontur di sebelahnya disebut...', '["A. Spot Height", "B. Skala", "C. Kontur Interval", "D. Elevasi"]'::jsonb, 'C. Kontur Interval'),
(20, 'Alat bantu yang digunakan bersama peta untuk mengukur jarak sebenarnya dari rute melengkung/berbelok-belok (seperti sungai atau jalan) disebut...', '["A. Altimeter", "B. Curvimeter", "C. Planimeter", "D. Kompas"]'::jsonb, 'B. Curvimeter'),
(20, 'Hal yang paling penting dilakukan jika seorang Pramuka menyadari bahwa dirinya benar-benar tersesat di hutan adalah...', '["A. Berlari mencari jalan secepatnya", "B. Membuang barang bawaan", "C. STOP (Stop, Thinking, Observe, Plan) - Berhenti, Tenang, Amati, dan Rencanakan", "D. Memanjat pohon tertinggi saat itu juga"]'::jsonb, 'C. STOP (Stop, Thinking, Observe, Plan) - Berhenti, Tenang, Amati, dan Rencanakan');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(24, 'Singkatan dari P3K adalah...', '["A. Pelatihan Pertama Pada Kecelakaan", "B. Pertolongan Pertama Pada Kecelakaan", "C. Pencegahan Pertama Pada Kecelakaan", "D. Penanganan Pasien Pada Kecelakaan"]'::jsonb, 'B. Pertolongan Pertama Pada Kecelakaan'),
(24, 'Tujuan utama dari P3K adalah...', '["A. Menggantikan peran dokter", "B. Menyelamatkan nyawa, mencegah cacat/kondisi memburuk, dan menunjang penyembuhan", "C. Menyembuhkan luka secara total", "D. Memberikan resep obat kepada korban"]'::jsonb, 'B. Menyelamatkan nyawa, mencegah cacat/kondisi memburuk, dan menunjang penyembuhan'),
(24, 'Tindakan yang TIDAK BOLEH dilakukan oleh seorang penolong pertama adalah...', '["A. Meminta bantuan medis/Ambulans", "B. Melakukan diagnosa medis pasti layaknya dokter", "C. Menjauhkan korban dari bahaya", "D. Menghentikan pendarahan luar"]'::jsonb, 'B. Melakukan diagnosa medis pasti layaknya dokter'),
(24, 'Saat menemukan korban kecelakaan, hal pertama yang harus diamati oleh penolong (Prinsip Dasar) adalah...', '["A. Mencari identitas korban", "B. Mengecek isi tas korban", "C. Memastikan keamanan lokasi (Aman Diri, Aman Lingkungan, Aman Korban)", "D. Langsung memberikan minum"]'::jsonb, 'C. Memastikan keamanan lokasi (Aman Diri, Aman Lingkungan, Aman Korban)'),
(24, 'Singkatan ABC dalam prinsip resusitasi/pertolongan pertama dasar pada korban tidak sadar merujuk pada...', '["A. Airway, Breathing, Circulation (Jalan napas, Pernapasan, Sirkulasi darah)", "B. Action, Blood, Care", "C. Accident, Bandage, CPR", "D. Alert, Breath, Call"]'::jsonb, 'A. Airway, Breathing, Circulation (Jalan napas, Pernapasan, Sirkulasi darah)'),
(24, 'Pendarahan yang darahnya keluar menyembur seirama dengan denyut jantung dan berwarna merah terang berasal dari pembuluh darah...', '["A. Vena (Balik)", "B. Kapiler (Rambut)", "C. Arteri (Nadi)", "D. Aorta"]'::jsonb, 'C. Arteri (Nadi)'),
(24, 'Pendarahan yang darahnya mengalir pelan/merembes dan berwarna merah gelap berasal dari pembuluh darah...', '["A. Arteri", "B. Vena (Balik)", "C. Jantung", "D. Paru-paru"]'::jsonb, 'B. Vena (Balik)'),
(24, 'Langkah pertama yang paling efektif untuk menghentikan pendarahan luar pada luka sayat adalah...', '["A. Mengoleskan tanah liat", "B. Menekan langsung di atas luka dengan kain bersih/kasa (Balut Tekan)", "C. Mengikat leher korban", "D. Mencuci dengan air sabun"]'::jsonb, 'B. Menekan langsung di atas luka dengan kain bersih/kasa (Balut Tekan)'),
(24, 'Alat berupa ikatan kuat di pangkal lengan/paha yang HANYA digunakan sebagai jalan terakhir pada pendarahan arteri hebat (amputasi) karena dapat mematikan jaringan disebut...', '["A. Bidai", "B. Mitela", "C. Tourniquet", "D. Kasa Steril"]'::jsonb, 'C. Tourniquet'),
(24, 'Pembalut berbentuk segitiga sama kaki yang terbuat dari kain putih (biasanya mori) yang sangat serbaguna dalam P3K disebut...', '["A. Plester", "B. Perban", "C. Mitela", "D. Funda"]'::jsonb, 'C. Mitela'),
(24, 'Mitela yang dilipat-lipat memanjang hingga bentuknya seperti pita selebar 5-10 cm disebut...', '["A. Bidai", "B. Cravat", "C. Tourniquet", "D. Kasa"]'::jsonb, 'B. Cravat'),
(24, 'Simpul yang paling sering digunakan untuk mengikat balutan mitela atau cravat karena mudah dilepas adalah...', '["A. Simpul Pangkal", "B. Simpul Mati (Reef Knot)", "C. Simpul Delapan", "D. Simpul Tiang"]'::jsonb, 'B. Simpul Mati (Reef Knot)'),
(24, 'Alat keras/kaku (seperti papan kayu, bambu, atau dahan lurus) yang digunakan untuk menjaga agar tulang yang patah tidak bergerak disebut...', '["A. Mitela", "B. Tourniquet", "C. Bidai (Spalk)", "D. Kruk"]'::jsonb, 'C. Bidai (Spalk)'),
(24, 'Tujuan utama dari tindakan pembidaian (pemasangan bidai) adalah...', '["A. Mengobati luka robek", "B. Imobilisasi (mencegah pergerakan) tulang yang patah agar jaringan di sekitarnya tidak rusak dan mengurangi nyeri", "C. Melancarkan peredaran darah", "D. Mengganti fungsi tulang"]'::jsonb, 'B. Imobilisasi (mencegah pergerakan) tulang yang patah agar jaringan di sekitarnya tidak rusak dan mengurangi nyeri'),
(24, 'Syarat utama bidai yang baik adalah...', '["A. Terbuat dari besi berat", "B. Panjangnya harus melewati dua sendi di antara tulang yang patah", "C. Harus sangat pendek agar praktis", "D. Harus lentur dan mudah ditekuk"]'::jsonb, 'B. Panjangnya harus melewati dua sendi di antara tulang yang patah'),
(24, 'Patah tulang di mana posisi tulang patah menembus kulit hingga terlihat dari luar disebut...', '["A. Fraktur Tertutup", "B. Fraktur Terbuka", "C. Dislokasi", "D. Memar"]'::jsonb, 'B. Fraktur Terbuka'),
(24, 'Tindakan yang BENAR jika menemui korban dengan patah tulang terbuka adalah...', '["A. Mendorong tulang masuk kembali ke dalam kulit", "B. Mencuci tulang dengan air sungai", "C. Tutup luka dengan kasa steril, hentikan pendarahan, pasang bidai tanpa menekan tulang yang menonjol", "D. Mengikat tulang dengan tali pramuka sekuatnya"]'::jsonb, 'C. Tutup luka dengan kasa steril, hentikan pendarahan, pasang bidai tanpa menekan tulang yang menonjol'),
(24, 'Cedera pada persendian di mana tulang keluar dari mangkuk sendinya disebut...', '["A. Fraktur (Patah Tulang)", "B. Dislokasi (Ceraib Sendi / Kesleo)", "C. Memar", "D. Kram"]'::jsonb, 'B. Dislokasi (Ceraib Sendi / Kesleo)'),
(24, 'Keadaan darurat di mana sistem peredaran darah gagal mengirimkan darah kaya oksigen ke organ vital tubuh, biasanya ditandai dengan kulit pucat, dingin, nadi cepat dan lemah, disebut...', '["A. Pingsan (Syncope)", "B. Shock (Syok)", "C. Dehidrasi", "D. Asma"]'::jsonb, 'B. Shock (Syok)'),
(24, 'Posisi pertolongan terbaik untuk korban yang mengalami Shock (syok) namun tidak ada indikasi cedera leher/kepala adalah...', '["A. Dudukkan korban di kursi", "B. Baringkan telentang dengan kaki diangkat lebih tinggi dari posisi jantung (Elevasi tungkai)", "C. Berdirikan korban dan paksa berjalan", "D. Posisikan tengkurap"]'::jsonb, 'B. Baringkan telentang dengan kaki diangkat lebih tinggi dari posisi jantung (Elevasi tungkai)'),
(24, 'Hilangnya kesadaran sementara akibat menurunnya aliran darah ke otak secara tiba-tiba disebut...', '["A. Syok", "B. Mati Suri", "C. Pingsan (Syncope)", "D. Koma"]'::jsonb, 'C. Pingsan (Syncope)'),
(24, 'Bila menjumpai teman yang tiba-tiba pingsan saat upacara, langkah P3K yang tepat adalah...', '["A. Menyiram air es ke wajahnya", "B. Bawa ke tempat teduh, baringkan, longgarkan pakaian/sabuk yang mengikat, dan beri udara segar", "C. Memukul punggungnya", "D. Memaksanya meminum air sirup saat masih tidak sadar"]'::jsonb, 'B. Bawa ke tempat teduh, baringkan, longgarkan pakaian/sabuk yang mengikat, dan beri udara segar'),
(24, 'Hal yang DILARANG keras dilakukan saat menolong orang yang tidak sadar / pingsan adalah...', '["A. Memberikan bau-bauan menyengat (minyak kayu putih)", "B. Melonggarkan kancing kerah baju", "C. Memasukkan air atau makanan ke dalam mulutnya", "D. Mengangkat kakinya sedikit"]'::jsonb, 'C. Memasukkan air atau makanan ke dalam mulutnya'),
(24, 'Kram otot yang parah sering terjadi saat kegiatan fisik yang berat. Penanganan utamanya adalah...', '["A. Kompres es dan paksa berlari", "B. Istirahatkan otot yang kram, lakukan peregangan ringan dan pijatan lembut ke arah jantung", "C. Ikat otot tersebut dengan tourniquet", "D. Tusuk dengan jarum"]'::jsonb, 'B. Istirahatkan otot yang kram, lakukan peregangan ringan dan pijatan lembut ke arah jantung'),
(24, 'Luka bakar yang ditandai dengan kulit hanya memerah, terasa panas dan nyeri (seperti terbakar sinar matahari parah) termasuk dalam luka bakar derajat...', '["A. Derajat 1", "B. Derajat 2", "C. Derajat 3", "D. Derajat 4"]'::jsonb, 'A. Derajat 1'),
(24, 'Luka bakar yang ditandai dengan munculnya gelembung berisi cairan (melepuh) pada kulit termasuk luka bakar derajat...', '["A. Derajat 1", "B. Derajat 2", "C. Derajat 3", "D. Derajat 4"]'::jsonb, 'B. Derajat 2'),
(24, 'Tindakan PERTAMA yang paling tepat untuk luka bakar akibat api atau air panas (Derajat 1 & 2 kecil) adalah...', '["A. Mengoleskan pasta gigi atau kecap", "B. Mengoleskan mentega", "C. Mengalirkan air bersih bersuhu biasa (bukan air es) pada luka selama 10-20 menit", "D. Memecahkan gelembung lepuhan"]'::jsonb, 'C. Mengalirkan air bersih bersuhu biasa (bukan air es) pada luka selama 10-20 menit'),
(24, 'Alasan medis mengapa DILARANG mengoleskan pasta gigi, oli, atau mentega pada luka bakar adalah...', '["A. Karena harganya mahal", "B. Dapat memerangkap panas di dalam jaringan kulit dan memicu infeksi hebat", "C. Karena membuat kulit berubah warna", "D. Karena akan menghentikan pendarahan"]'::jsonb, 'B. Dapat memerangkap panas di dalam jaringan kulit dan memicu infeksi hebat'),
(24, 'Pertolongan pertama jika bagian tubuh terciprat zat kimia asam/basa kuat adalah...', '["A. Lap dengan handuk kering saja", "B. Segera bilas dan guyur dengan air mengalir dalam jumlah sangat banyak minimal 20 menit", "C. Netralkan asam dengan deterjen", "D. Biarkan hingga kering sendiri"]'::jsonb, 'B. Segera bilas dan guyur dengan air mengalir dalam jumlah sangat banyak minimal 20 menit'),
(24, 'Tindakan yang paling tepat saat menolong korban gigitan ular beracun di hutan adalah...', '["A. Menyedot bisa/racun dengan mulut penolong", "B. Membelah luka gigitan dengan pisau silet", "C. Mengikat sangat kuat (tourniquet) di atas luka agar darah berhenti", "D. Imobilisasi (bidai) bagian yang digigit agar tidak bergerak, posisikan lebih rendah dari jantung, dan evakuasi segera ke RS"]'::jsonb, 'D. Imobilisasi (bidai) bagian yang digigit agar tidak bergerak, posisikan lebih rendah dari jantung, dan evakuasi segera ke RS'),
(24, 'Jika seseorang tersedak makanan dan memegangi lehernya serta tidak bisa bernapas/bersuara, manuver P3K yang harus segera dilakukan adalah...', '["A. Manuver Heimlich (Heimlich Maneuver / Hentakan perut)", "B. CPR (Resusitasi Jantung Paru)", "C. Memberi napas buatan dari mulut", "D. Menyiram air es"]'::jsonb, 'A. Manuver Heimlich (Heimlich Maneuver / Hentakan perut)'),
(24, 'Pertolongan pada korban mimisan (pendarahan hidung) yang benar adalah...', '["A. Menengadahkan kepala jauh ke belakang", "B. Menundukkan kepala sedikit ke depan dan menekan cuping hidung selama 5-10 menit", "C. Memasukkan jari ke dalam hidung", "D. Menyuruh korban meniup hidung dengan keras"]'::jsonb, 'B. Menundukkan kepala sedikit ke depan dan menekan cuping hidung selama 5-10 menit'),
(24, 'Zat antiseptik yang umum digunakan dalam kotak P3K untuk membersihkan luka gores dan mencegah infeksi adalah...', '["A. Minyak kayu putih", "B. Povidone Iodine (Betadine) atau Rivanol", "C. Balsem", "D. Sirup parasetamol"]'::jsonb, 'B. Povidone Iodine (Betadine) atau Rivanol'),
(24, 'Cara terbaik membersihkan luka lecet yang kotor karena jatuh di aspal adalah...', '["A. Digosok dengan kapas kering", "B. Dicuci bersih menggunakan air mengalir (dan sabun ringan di area sekitar luka), lalu diberi antiseptik", "C. Langsung ditaburi bedak luka", "D. Dibiarkan terbuka tanpa dicuci"]'::jsonb, 'B. Dicuci bersih menggunakan air mengalir (dan sabun ringan di area sekitar luka), lalu diberi antiseptik'),
(24, 'Jika terdapat benda asing (kaca/kayu) menancap cukup dalam pada luka, tindakan penolong yang benar adalah...', '["A. Mencabut benda tersebut secepatnya", "B. Memutar benda tersebut agar mudah ditarik", "C. JANGAN dicabut, amankan (imobilisasi) benda tersebut dengan balutan tebal di sekelilingnya agar tidak goyang, evakuasi medis", "D. Membakar ujung benda tersebut"]'::jsonb, 'C. JANGAN dicabut, amankan (imobilisasi) benda tersebut dengan balutan tebal di sekelilingnya agar tidak goyang, evakuasi medis'),
(24, 'Teknik RJP (Resusitasi Jantung Paru) atau CPR diberikan kepada korban yang mengalami kondisi...', '["A. Pingsan biasa", "B. Henti Napas dan Henti Jantung (Nadi tidak teraba)", "C. Patah tulang", "D. Pendarahan hidung"]'::jsonb, 'B. Henti Napas dan Henti Jantung (Nadi tidak teraba)'),
(24, 'Rasio standar internasional (AHA) untuk kompresi dada dan napas buatan pada RJP orang dewasa adalah...', '["A. 15 kompresi : 2 napas", "B. 30 kompresi : 2 napas", "C. 5 kompresi : 1 napas", "D. 10 kompresi : 5 napas"]'::jsonb, 'B. 30 kompresi : 2 napas'),
(24, 'Titik lokasi untuk melakukan penekanan (kompresi) dada saat CPR adalah...', '["A. Di atas perut bagian atas", "B. Di leher", "C. Di pertengahan tulang dada (Sternum)", "D. Di tulang rusuk kiri"]'::jsonb, 'C. Di pertengahan tulang dada (Sternum)'),
(24, 'Bila seseorang dicurigai keracunan makanan yang ditelan baru saja terjadi (dan korban masih SADAR penuh, bukan menelan zat asam/korosif), tindakan P3K yang disarankan adalah...', '["A. Beri minum air putih hangat/susu/Norit untuk mengencerkan racun dan merangsang muntah", "B. Beri makan buah jeruk", "C. Suruh korban tidur tengkurap", "D. Berikan napas buatan"]'::jsonb, 'A. Beri minum air putih hangat/susu/Norit untuk mengencerkan racun dan merangsang muntah'),
(24, 'Keracunan akibat menghirup gas beracun (seperti karbon monoksida dari asap genset). Tindakan pertama adalah...', '["A. Memberi minum air putih", "B. Menyalakan api di sekitar korban", "C. Pindahkan korban segera ke area terbuka dengan udara segar dan periksa pernapasan", "D. Menutup hidung korban dengan kain basah selamanya"]'::jsonb, 'C. Pindahkan korban segera ke area terbuka dengan udara segar dan periksa pernapasan'),
(24, 'Gigitan anjing, kucing, atau kera liar sangat berbahaya karena berisiko menularkan virus yang menyerang saraf pusat, yaitu...', '["A. Virus Dengue", "B. Virus Rabies (Penyakit Anjing Gila)", "C. Virus HIV", "D. Tetanus"]'::jsonb, 'B. Virus Rabies (Penyakit Anjing Gila)'),
(24, 'Pertolongan pertama luka gigitan hewan berisiko rabies sebelum dibawa ke rumah sakit adalah...', '["A. Mencuci luka dengan air mengalir dan sabun selama 10-15 menit agar virus luruh", "B. Membakar luka gigitan", "C. Menghisap darah dari luka gigitan", "D. Mengolesi luka dengan tanah"]'::jsonb, 'A. Mencuci luka dengan air mengalir dan sabun selama 10-15 menit agar virus luruh'),
(24, 'Untuk mengangkat dan memindahkan korban yang dicurigai mengalami cedera tulang belakang (leher/punggung), cara evakuasi yang TEPAT adalah...', '["A. Digendong di punggung", "B. Diangkat oleh satu orang dari depan", "C. Ditarik tangannya", "D. Diangkat secara bersama-sama (Log roll) menjaga posisi kepala-leher-tulang punggung tetap lurus kaku pada tandu keras"]'::jsonb, 'D. Diangkat secara bersama-sama (Log roll) menjaga posisi kepala-leher-tulang punggung tetap lurus kaku pada tandu keras'),
(24, 'Tindakan mengompres memar akibat benturan benda tumpul dalam 24 jam pertama sebaiknya menggunakan...', '["A. Air panas", "B. Es batu / Air dingin (Cold pack) untuk menyempitkan pembuluh darah dan mengurangi bengkak", "C. Minyak kayu putih panas", "D. Alkohol 70%"]'::jsonb, 'B. Es batu / Air dingin (Cold pack) untuk menyempitkan pembuluh darah dan mengurangi bengkak'),
(24, 'Korban yang mengalami kedinginan hebat (suhu tubuh turun drastis di bawah 35 derajat celcius) saat mendaki gunung disebut mengalami...', '["A. Hipertermia", "B. Hipotermia", "C. Dehidrasi", "D. Hipoksia"]'::jsonb, 'B. Hipotermia'),
(24, 'Penanganan utama untuk korban Hipotermia adalah...', '["A. Buka semua bajunya dan biarkan ditiup angin", "B. Berikan minuman beralkohol", "C. Ganti pakaian basah dengan yang kering, selimuti dengan thermal blanket/selimut tebal, dan beri minuman hangat manis jika sadar", "D. Rendam korban ke dalam air panas"]'::jsonb, 'C. Ganti pakaian basah dengan yang kering, selimuti dengan thermal blanket/selimut tebal, dan beri minuman hangat manis jika sadar'),
(24, 'Kondisi kelelahan akibat panas ekstrem (Heat Exhaustion) harus segera ditangani dengan cara...', '["A. Membiarkan berjemur", "B. Membawa korban ke tempat sejuk, beri minum oralit/air mendinginkan tubuh dengan kompres basah", "C. Memakaikan jaket tebal", "D. Memberi makanan panas"]'::jsonb, 'B. Membawa korban ke tempat sejuk, beri minum oralit/air mendinginkan tubuh dengan kompres basah'),
(24, 'Buku saku catatan medis kecil yang dibawa Pramuka untuk mendata golongan darah dan alergi anggotanya dinamakan...', '["A. Buku Saku P3K", "B. Buku Tabungan", "C. Buku SKU", "D. Logbook Pasien"]'::jsonb, 'A. Buku Saku P3K'),
(24, 'Pemindahan korban dalam keadaan sangat darurat (misal: mobil terbakar) yang dilakukan oleh 1 orang penolong tanpa alat disebut...', '["A. Tandu darurat", "B. Evakuasi Darurat (Emergency Move)", "C. Evakuasi Medis Terencana", "D. Log Roll"]'::jsonb, 'B. Evakuasi Darurat (Emergency Move)'),
(24, 'Asas terpenting yang harus diingat penolong sebelum melakukan P3K di jalanan raya adalah...', '["A. Jangan menolong jika tidak dibayar", "B. Penolong harus memastikan keselamatan dirinya sendiri terlebih dahulu sebelum menolong korban (Aman Diri)", "C. Langsung melompat ke tengah jalan", "D. Mencari wartawan untuk difoto"]'::jsonb, 'B. Penolong harus memastikan keselamatan dirinya sendiri terlebih dahulu sebelum menolong korban (Aman Diri)');